    `app_size_mb` DECIMAL(18,2) COMMENT 'The total download size of the application package in megabytes. Important for user download experience and app store requirements. | Column app_size_mb (DECIMAL(10,2)) in distribution.app_version',
    `build_number` STRING COMMENT 'Internal build identifier assigned by the continuous integration system. Used for precise version tracking and debugging. May be numeric or alphanumeric. | Column build_number (STRING) in distribution.app_version',
    `ccpa_compliant` BOOLEAN COMMENT 'Indicates whether this application version meets CCPA (California Consumer Privacy Act) requirements for viewer data privacy in California. | Column ccpa_compliant (BOOLEAN) in distribution.app_version',
    `cdn_endpoint_url` STRING COMMENT 'The primary CDN (Content Delivery Network) endpoint URL configured for this application version. Determines content delivery infrastructure and streaming performance. | Column cdn_endpoint_url (STRING) in distribution.app_version',
    `closed_caption_support` BOOLEAN COMMENT 'Indicates whether this application version supports closed captioning and subtitles for accessibility compliance. | Column closed_caption_support (BOOLEAN) in distribution.app_version',
    `crash_reporting_enabled` BOOLEAN COMMENT 'Indicates whether automated crash reporting and error tracking is enabled for this application version. Critical for QoS root-cause analysis. | Column crash_reporting_enabled (BOOLEAN) in distribution.app_version',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.app_version',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this application version record was first created in the system. Used for audit trail and version history tracking. | Column created_timestamp (TIMESTAMP) in distribution.app_version',
    `dai_enabled` BOOLEAN COMMENT 'Indicates whether this application version supports DAI (Dynamic Ad Insertion) for server-side ad stitching in streaming content. | Column dai_enabled (BOOLEAN) in distribution.app_version',
