CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`streaming_endpoint` (
    `streaming_endpoint_id` BIGINT COMMENT 'Unique identifier for the streaming endpoint. Primary key for the streaming endpoint master record. | Column streaming_endpoint_id (BIGINT) in distribution.streaming_endpoint',
    `abr_profile_id` BIGINT COMMENT 'Foreign key linking to distribution.abr_profile. Business justification: Streaming endpoints use specific ABR profiles. streaming_endpoint.abr_profile_reference is STRING but should FK to abr_profile master. Removes abr_profile_reference STRING. | Column abr_profile_id (BIGINT) in distribution.streaming_endpoint',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: Streaming endpoints are physically hosted in broadcast facilities. Required for facility outage impact analysis, power/cooling capacity planning, and physical security management. | Column broadcast_facility_id (BIGINT) in technology.streaming_endpoint',
    `broadcast_license_id` BIGINT COMMENT 'Foreign key linking to compliance.broadcast_license. Business justification: Streaming endpoints delivering broadcast content must comply with originating broadcast license terms for geographic restrictions, transmission standards, and regulatory reporting. License governs end | Column broadcast_license_id (BIGINT) in compliance.streaming_endpoint',
    `cdn_configuration_id` BIGINT COMMENT 'Foreign key linking to distribution.cdn_configuration. Business justification: Streaming endpoints use specific CDN configurations. streaming_endpoint.cdn_provider is STRING but should FK to cdn_configuration. Removes cdn_provider STRING. | Column cdn_configuration_id (BIGINT) in distribution.streaming_endpoint',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Streaming endpoints incur CDN and hosting costs that must be allocated to technology cost centers for chargeback and budget management. Monthly CDN invoice reconciliation allocates bandwidth and compu | Column cost_center_id (BIGINT) in finance.streaming_endpoint',
    `dai_configuration_id` BIGINT COMMENT 'Foreign key linking to distribution.dai_configuration. Business justification: Streaming endpoints can have default DAI configurations. Removes dai_provider STRING (derivable from dai_configuration). | Column dai_configuration_id (BIGINT) in distribution.streaming_endpoint',
    `drm_policy_id` BIGINT COMMENT 'Foreign key linking to distribution.drm_policy. Business justification: Streaming endpoints enforce specific DRM policies. streaming_endpoint.drm_system is STRING but should FK to drm_policy. Removes drm_system STRING (derivable from drm_policy.drm_system). | Column drm_policy_id (BIGINT) in distribution.streaming_endpoint',
    `encoder_config_id` BIGINT COMMENT 'Foreign key linking to technology.encoder_config. Business justification: Streaming endpoints receive feeds from encoder configurations. Required for encoder-endpoint signal routing and configuration management. | Column encoder_config_id (BIGINT) in technology.streaming_endpoint',
    `failover_endpoint_id` BIGINT COMMENT 'Reference to the backup streaming endpoint that should be used if this endpoint becomes unavailable. Supports high availability and disaster recovery. | Column failover_endpoint_id (BIGINT) in distribution.streaming_endpoint',
    `maintenance_work_order_id` BIGINT COMMENT 'Foreign key linking to technology.maintenance_work_order. Business justification: Streaming endpoints require maintenance work orders for updates and repairs. Required for endpoint maintenance history and downtime impact tracking. | Column maintenance_work_order_id (BIGINT) in technology.streaming_endpoint',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: CDN endpoints serve specific DMAs for geo-restriction enforcement, local ad insertion, and market-specific content delivery. Required for retransmission consent compliance and must-carry obligations i | Column market_coverage_id (BIGINT) in audience.streaming_endpoint',
    `network_circuit_id` BIGINT COMMENT 'Foreign key linking to technology.network_circuit. Business justification: Streaming endpoints rely on network circuits for connectivity. Required for circuit capacity planning and endpoint failover configuration. | Column network_circuit_id (BIGINT) in technology.streaming_endpoint',
    `noc_monitor_id` BIGINT COMMENT 'Foreign key linking to technology.noc_monitor. Business justification: Streaming endpoints have assigned NOC monitors tracking uptime and latency. Required for NOC monitoring configuration and alert routing. | Column noc_monitor_id (BIGINT) in technology.streaming_endpoint',
    `ott_platform_id` BIGINT COMMENT 'Foreign key linking to distribution.ott_platform. Business justification: Streaming endpoints are provisioned for specific OTT platforms. Each endpoint serves content for a platform. No visible platform_type column but relationship is essential for endpoint management. | Column ott_platform_id (BIGINT) in distribution.streaming_endpoint',
    `outage_record_id` BIGINT COMMENT 'Foreign key linking to technology.outage_record. Business justification: Streaming endpoints experience outages requiring tracking. Required for endpoint availability reporting and outage pattern analysis. | Column outage_record_id (BIGINT) in technology.streaming_endpoint',
    `rights_territory_id` BIGINT COMMENT 'Foreign key linking to rights.territory. Business justification: Streaming endpoints serve specific geographic territories. Essential for enforcing geo-restriction rules per rights grants, validating territory-based rights compliance, and routing playback sessions  | Column rights_territory_id (BIGINT) in rights.streaming_endpoint',
    `sla_definition_id` BIGINT COMMENT 'Foreign key linking to distribution.sla_definition. Business justification: Streaming endpoints have SLA commitments. streaming_endpoint.sla_tier is STRING but should FK to sla_definition. Removes sla_tier STRING (derivable from sla_definition.sla_tier). | Column sla_definition_id (BIGINT) in distribution.streaming_endpoint',
    `software_license_id` BIGINT COMMENT 'Foreign key linking to technology.software_license. Business justification: Streaming endpoints run licensed CDN and DRM software. Required for software license compliance tracking and endpoint cost allocation. | Column software_license_id (BIGINT) in technology.streaming_endpoint',
    `tech_project_id` BIGINT COMMENT 'Foreign key linking to technology.tech_project. Business justification: Streaming endpoints are deployed via CDN expansion projects. Required for CDN project ROI analysis and endpoint deployment timeline tracking. | Column tech_project_id (BIGINT) in technology.streaming_endpoint',
    `tech_sla_id` BIGINT COMMENT 'Foreign key linking to technology.tech_sla. Business justification: Streaming endpoints have technology SLAs for uptime and latency. Required for endpoint SLA compliance reporting and performance benchmarking. | Column tech_sla_id (BIGINT) in technology.streaming_endpoint',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Streaming endpoints are critical infrastructure requiring technical ownership for incident response, maintenance windows, configuration changes, and failover testing. Essential for on-call rotations,  | Column technical_owner_employee_id (BIGINT) in workforce.streaming_endpoint',
    `technical_standard_cert_id` BIGINT COMMENT 'Foreign key linking to compliance.technical_standard_cert. Business justification: Streaming endpoints must be certified against technical standards (HLS spec, DASH spec, DRM robustness, accessibility). Each endpoint references its certification records for compliance validation. | Column technical_standard_cert_id (BIGINT) in compliance.streaming_endpoint',
    `transmission_equipment_id` BIGINT COMMENT 'Foreign key linking to technology.transmission_equipment. Business justification: Streaming endpoints rely on transmission equipment (encoders, transcoders). Required for equipment failure impact analysis and encoder capacity management. | Column transmission_equipment_id (BIGINT) in technology.streaming_endpoint',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in distribution.streaming_endpoint',
    `_source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in distribution.streaming_endpoint',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in distribution.streaming_endpoint',
    `activated_timestamp` TIMESTAMP COMMENT 'The date and time when this endpoint was first activated and began serving live traffic. | Column activated_timestamp (TIMESTAMP) in distribution.streaming_endpoint',
    `bandwidth_limit_gbps` DECIMAL(18,2) COMMENT 'Maximum aggregate bandwidth capacity in gigabits per second allocated to this endpoint. Used for capacity planning and cost management. | Column bandwidth_limit_gbps (DECIMAL(10,2)) in distribution.streaming_endpoint',
    `cache_ttl_seconds` STRING COMMENT 'The duration in seconds that content should be cached at edge locations before refreshing from origin. Balances freshness with CDN efficiency. | Column cache_ttl_seconds (INT) in distribution.streaming_endpoint',
    `cost_per_gb` DECIMAL(18,2) COMMENT 'The CDN providers charge per gigabyte of data transferred through this endpoint. Used for cost allocation and financial forecasting. | Column cost_per_gb (DECIMAL(10,4)) in distribution.streaming_endpoint',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.streaming_endpoint',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this streaming endpoint record was first created in the system. | Column created_timestamp (TIMESTAMP) in distribution.streaming_endpoint',
    `dai_enabled` BOOLEAN COMMENT 'Indicates whether this endpoint supports Dynamic Ad Insertion, allowing personalized ads to be stitched into the stream in real-time. | Column dai_enabled (BOOLEAN) in distribution.streaming_endpoint',
    `deactivated_timestamp` TIMESTAMP COMMENT 'The date and time when this endpoint was deactivated or taken out of service. Null if currently active. | Column deactivated_timestamp (TIMESTAMP) in distribution.streaming_endpoint',
    `drm_license_server_url` STRING COMMENT 'URL of the DRM license server that provides decryption keys and enforces content protection policies for this endpoint. Critical for securing premium content. | Column drm_license_server_url (STRING) in distribution.streaming_endpoint. Valid values are `^https?://[a-zA-Z0-9.-]+(/[a-zA-Z0-9._~:/?#[]@!$&()*+,;=-]*)?$`',
    `endpoint_name` STRING COMMENT 'Human-readable name or label for the streaming endpoint, used for identification and operational reference. | Column endpoint_name (STRING) in distribution.streaming_endpoint',
    `endpoint_type` STRING COMMENT 'Classification of the endpoint role within the CDN architecture. Origin endpoints serve as the source, edge endpoints serve end users, and backup endpoints provide failover capability. | Column endpoint_type (STRING) in distribution.streaming_endpoint. Valid values are `origin|edge|backup`',
    `endpoint_url` STRING COMMENT 'The full URL address of the streaming endpoint, including protocol, domain, and path. This is the technical delivery address for the stream. | Column endpoint_url (STRING) in distribution.streaming_endpoint. Valid values are `^https?://[a-zA-Z0-9.-]+(/[a-zA-Z0-9._~:/?#[]@!$&()*+,;=-]*)?$`',
    `geo_restriction_mode` STRING COMMENT 'Defines whether geo_restriction_rules represent an allow list (whitelist) or deny list (blacklist) for content delivery. | Column geo_restriction_mode (STRING) in distribution.streaming_endpoint. Valid values are `whitelist|blacklist|none`',
    `geo_restriction_rules` STRING COMMENT 'Comma-separated list of ISO country codes or regions where content delivery is allowed or blocked. Enforces territorial licensing and rights management requirements. | Column geo_restriction_rules (STRING) in distribution.streaming_endpoint',
    `health_check_interval_seconds` STRING COMMENT 'Frequency in seconds at which automated health checks are performed against this endpoint. | Column health_check_interval_seconds (INT) in distribution.streaming_endpoint',
    `health_check_url` STRING COMMENT 'URL endpoint used for automated health monitoring and availability checks. Returns status codes indicating endpoint health. | Column health_check_url (STRING) in distribution.streaming_endpoint. Valid values are `^https?://[a-zA-Z0-9.-]+(/[a-zA-Z0-9._~:/?#[]@!$&()*+,;=-]*)?$`',
    `ipv6_enabled` BOOLEAN COMMENT 'Indicates whether this endpoint supports IPv6 addressing in addition to IPv4, enabling delivery to modern network infrastructures. | Column ipv6_enabled (BOOLEAN) in distribution.streaming_endpoint',
    `last_health_check_timestamp` TIMESTAMP COMMENT 'The date and time of the most recent successful health check performed on this endpoint. | Column last_health_check_timestamp (TIMESTAMP) in distribution.streaming_endpoint',
    `manifest_format` STRING COMMENT 'The streaming manifest file format used by this endpoint. m3u8 for HLS, mpd for MPEG-DASH, ism for Smooth Streaming, f4m for Adobe HDS. | Column manifest_format (STRING) in distribution.streaming_endpoint. Valid values are `m3u8|mpd|ism|f4m`',
    `max_bitrate_mbps` DECIMAL(18,2) COMMENT 'The maximum streaming bitrate in megabits per second that this endpoint can deliver. Defines the upper quality limit for adaptive streaming. | Column max_bitrate_mbps (DECIMAL(10,2)) in distribution.streaming_endpoint',
    `modified_timestamp` TIMESTAMP COMMENT 'The date and time when this streaming endpoint record was last modified or updated. | Column modified_timestamp (TIMESTAMP) in distribution.streaming_endpoint',
    `operational_status` STRING COMMENT 'Current operational state of the streaming endpoint. Active endpoints are serving traffic; inactive endpoints are provisioned but not in use; maintenance indicates scheduled downtime. | Column operational_status (STRING) in distribution.streaming_endpoint. Valid values are `active|inactive|maintenance|degraded|failed`',
    `provisioned_date` DATE COMMENT 'The date when this streaming endpoint was initially provisioned and configured in the CDN infrastructure. | Column provisioned_date (DATE) in distribution.streaming_endpoint',
    `sla_uptime_target_percent` DECIMAL(18,2) COMMENT 'The contractual uptime percentage target for this endpoint (e.g., 99.99%). Used for SLA compliance monitoring and vendor accountability. | Column sla_uptime_target_percent (DECIMAL(5,2)) in distribution.streaming_endpoint',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.streaming_endpoint',
    `ssl_certificate_expiry_date` DATE COMMENT 'Expiration date of the SSL/TLS certificate securing this endpoint. Critical for maintaining secure HTTPS delivery and avoiding service disruptions. | Column ssl_certificate_expiry_date (DATE) in distribution.streaming_endpoint',
    `streaming_protocol` STRING COMMENT 'The streaming protocol used by this endpoint for content delivery. HLS (HTTP Live Streaming) and MPEG-DASH (Dynamic Adaptive Streaming over HTTP) are the most common adaptive bitrate protocols. | Column streaming_protocol (STRING) in distribution.streaming_endpoint. Valid values are `HLS|MPEG-DASH|RTMP|WebRTC|Smooth Streaming`',
    `supported_devices` STRING COMMENT 'Comma-separated list of device types or platforms that this endpoint is optimized to serve (e.g., iOS, Android, Smart TV, Web Browser, Set-Top Box). | Column supported_devices (STRING) in distribution.streaming_endpoint',
    `token_authentication_scheme` STRING COMMENT 'The authentication mechanism used to secure access to the endpoint. Prevents unauthorized access and hotlinking through cryptographic token validation. | Column token_authentication_scheme (STRING) in distribution.streaming_endpoint. Valid values are `JWT|HMAC|Akamai Token|AWS Signature|None`',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.streaming_endpoint',
    CONSTRAINT pk_streaming_endpoint PRIMARY KEY(`streaming_endpoint_id`)
) COMMENT 'Master record of all streaming origin and edge endpoints managed across the CDN infrastructure (Akamai CDN). Captures endpoint URL, CDN provider, PoP (Point of Presence) region, protocol (HLS, MPEG-DASH), ABR ladder configuration reference, DRM license server URL, token authentication scheme, geo-restriction rules, failover endpoint reference, SLA tier, and operational status. SSOT for the technical delivery address of each stream. | Unity Catalog table: media_broadcasting_ecm.distribution.streaming_endpoint';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`abr_profile` (
    `abr_profile_id` BIGINT COMMENT 'Unique identifier for the ABR encoding ladder profile. Primary key. | Column abr_profile_id (BIGINT) in distribution.abr_profile',
    `broadcast_standard_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_standard. Business justification: ABR profiles implement broadcast standards (HLS, DASH). Required for broadcast standard compliance verification and device interoperability testing. | Column broadcast_standard_id (BIGINT) in technology.abr_profile',
    `encoder_config_id` BIGINT COMMENT 'Foreign key linking to technology.encoder_config. Business justification: ABR profiles are generated by encoder configurations. Required for encoder profile assignment and video quality troubleshooting. | Column encoder_config_id (BIGINT) in technology.abr_profile',
    `format_specification_id` BIGINT COMMENT 'Foreign key linking to mediaasset.format_specification. Business justification: ABR profiles implement technical delivery standards (codec, bitrate ladder, resolution tiers) defined in format specifications. Broadcasters validate ABR configs against house specs for compliance. Qo | Column format_specification_id (BIGINT) in mediaasset.abr_profile',
    `technical_standard_cert_id` BIGINT COMMENT 'Foreign key linking to compliance.technical_standard_cert. Business justification: ABR profiles must comply with codec standards, streaming protocol specifications, and accessibility requirements. Profile certification validates compliance with technical standards before deployment. | Column technical_standard_cert_id (BIGINT) in compliance.abr_profile',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in distribution.abr_profile',
    `_source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in distribution.abr_profile',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in distribution.abr_profile',
    `audio_bitrate_kbps` STRING COMMENT 'Audio bitrate in kilobits per second (e.g., 128, 192, 256). Defines audio quality. | Column audio_bitrate_kbps (INT) in distribution.abr_profile',
    `audio_channel_config` STRING COMMENT 'Audio channel layout (mono, stereo, 5.1 surround, 7.1 surround, Dolby Atmos). Defines spatial audio configuration. | Column audio_channel_config (STRING) in distribution.abr_profile. Valid values are `mono|stereo|5.1|7.1|Atmos`',
    `audio_codec` STRING COMMENT 'Audio codec used for encoding (AAC, HE-AAC, AC-3/Dolby Digital, E-AC-3/Dolby Digital Plus, Opus). | Column audio_codec (STRING) in distribution.abr_profile. Valid values are `AAC|HE-AAC|AC-3|E-AC-3|Opus`',
    `cdn_optimization_flag` BOOLEAN COMMENT 'Indicates whether the profile is optimized for CDN delivery with caching-friendly segment naming and structure. True if CDN-optimized; false otherwise. | Column cdn_optimization_flag (BOOLEAN) in distribution.abr_profile',
    `color_space` STRING COMMENT 'Color space standard used for encoding (BT.709 for HD, BT.2020 for UHD/HDR, DCI-P3 for cinema). | Column color_space (STRING) in distribution.abr_profile. Valid values are `BT.709|BT.2020|DCI-P3`',
    `container_format` STRING COMMENT 'Media container format for the encoded segments (fMP4 for DASH, TS for HLS, MP4, WebM). Defines how video and audio streams are packaged. | Column container_format (STRING) in distribution.abr_profile. Valid values are `fMP4|TS|MP4|WebM`',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.abr_profile',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the ABR profile record was first created in the system. | Column created_timestamp (TIMESTAMP) in distribution.abr_profile',
    `drm_support_flag` BOOLEAN COMMENT 'Indicates whether the profile supports DRM encryption. True if DRM is enabled; false otherwise. | Column drm_support_flag (BOOLEAN) in distribution.abr_profile',
    `drm_system` STRING COMMENT 'DRM system(s) supported by this profile (Widevine, PlayReady, FairPlay Streaming, Multi-DRM). Null if DRM is not enabled. | Column drm_system (STRING) in distribution.abr_profile. Valid values are `Widevine|PlayReady|FairPlay|Multi-DRM`',
    `effective_date` DATE COMMENT 'Date when the ABR profile became active and available for use in production encoding workflows. | Column effective_date (DATE) in distribution.abr_profile',
    `encoding_preset` STRING COMMENT 'Encoder speed/quality preset (fast, medium, slow, veryslow). Slower presets yield better compression but require more processing time. | Column encoding_preset (STRING) in distribution.abr_profile. Valid values are `fast|medium|slow|veryslow`',
    `expiration_date` DATE COMMENT 'Date when the ABR profile is scheduled to be deprecated or retired. Null for profiles with no planned end date. | Column expiration_date (DATE) in distribution.abr_profile',
    `frame_rate` DECIMAL(18,2) COMMENT 'Target frame rate for video renditions (e.g., 23.976, 25, 29.97, 30, 50, 59.94, 60). May vary by rendition. | Column frame_rate (DECIMAL(18,2)) in distribution.abr_profile',
    `hdr_format` STRING COMMENT 'Specific HDR format supported (HDR10, HDR10+, Dolby Vision, HLG). Null if HDR is not supported. | Column hdr_format (STRING) in distribution.abr_profile. Valid values are `HDR10|HDR10+|Dolby Vision|HLG`',
    `hdr_support_flag` BOOLEAN COMMENT 'Indicates whether the profile supports HDR (High Dynamic Range) video. True if HDR is enabled; false for SDR (Standard Dynamic Range) only. | Column hdr_support_flag (BOOLEAN) in distribution.abr_profile',
    `keyframe_interval_seconds` STRING COMMENT 'Interval between keyframes (I-frames) in seconds. Aligns with segment duration for seamless ABR switching. | Column keyframe_interval_seconds (INT) in distribution.abr_profile',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when the ABR profile record was last updated or modified. | Column last_modified_timestamp (TIMESTAMP) in distribution.abr_profile',
    `manifest_template_reference` STRING COMMENT 'Reference to the MPEG-DASH MPD or HLS M3U8 manifest template used for this profile. Defines playlist structure and metadata. | Column manifest_template_reference (STRING) in distribution.abr_profile',
    `max_bitrate_kbps` STRING COMMENT 'Highest video bitrate in kilobits per second across all renditions in the ladder. Used for high-quality streaming on fast connections. | Column max_bitrate_kbps (INT) in distribution.abr_profile',
    `max_resolution` STRING COMMENT 'Highest video resolution in the ladder (e.g., 1920x1080, 3840x2160). Defines the top quality tier. | Column max_resolution (STRING) in distribution.abr_profile',
    `min_bitrate_kbps` STRING COMMENT 'Lowest video bitrate in kilobits per second across all renditions in the ladder. Used for low-bandwidth scenarios. | Column min_bitrate_kbps (INT) in distribution.abr_profile',
    `min_resolution` STRING COMMENT 'Lowest video resolution in the ladder (e.g., 320x180, 640x360). Typically used for mobile or constrained bandwidth. | Column min_resolution (STRING) in distribution.abr_profile',
    `owner_team` STRING COMMENT 'Name of the engineering or operations team responsible for maintaining and updating this ABR profile. | Column owner_team (STRING) in distribution.abr_profile',
    `profile_code` STRING COMMENT 'Unique business identifier code for the ABR profile used in transcode job requests and CDN configuration. | Column profile_code (STRING) in distribution.abr_profile',
    `profile_description` STRING COMMENT 'Detailed description of the ABR profile, including use cases, target audience, and technical notes. | Column profile_description (STRING) in distribution.abr_profile',
    `profile_name` STRING COMMENT 'Human-readable name of the ABR profile (e.g., Premium 4K HDR, Standard HD, Mobile Optimized). | Column profile_name (STRING) in distribution.abr_profile',
    `profile_status` STRING COMMENT 'Current lifecycle status of the ABR profile. Active profiles are used in production encoding; deprecated profiles are phased out; testing profiles are under validation; inactive profiles are disabled. | Column profile_status (STRING) in distribution.abr_profile. Valid values are `active|deprecated|testing|inactive`',
    `qos_tier` STRING COMMENT 'Quality of Service tier associated with this profile (premium, standard, basic). Influences CDN priority and SLA commitments. | Column qos_tier (STRING) in distribution.abr_profile. Valid values are `premium|standard|basic`',
    `rendition_count` STRING COMMENT 'Total number of video renditions (bitrate/resolution variants) in the ABR ladder. Typical range is 3-10 renditions. | Column rendition_count (INT) in distribution.abr_profile',
    `segment_duration_seconds` STRING COMMENT 'Duration of each media segment in seconds (e.g., 2, 4, 6, 10). Shorter segments enable faster ABR switching but increase overhead. | Column segment_duration_seconds (INT) in distribution.abr_profile',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.abr_profile',
    `streaming_protocol` STRING COMMENT 'Adaptive bitrate streaming protocol supported by this profile (HLS, MPEG-DASH, CMAF, Smooth Streaming). | Column streaming_protocol (STRING) in distribution.abr_profile. Valid values are `HLS|MPEG-DASH|CMAF|Smooth Streaming`',
    `target_device_class` STRING COMMENT 'Primary device class this profile is optimized for (mobile, tablet, desktop, smart TV, set-top box, gaming console). Influences resolution and bitrate choices. | Column target_device_class (STRING) in distribution.abr_profile. Valid values are `mobile|tablet|desktop|smart_tv|set_top_box|gaming_console`',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.abr_profile',
    `version_number` STRING COMMENT 'Version number of the ABR profile. Incremented with each significant change to the encoding ladder or configuration. | Column version_number (INT) in distribution.abr_profile',
    `video_codec` STRING COMMENT 'Primary video codec used for encoding (H.264/AVC, H.265/HEVC, AV1, VP9). Determines compression efficiency and device compatibility. | Column video_codec (STRING) in distribution.abr_profile. Valid values are `H.264|H.265|HEVC|AV1|VP9`',
    CONSTRAINT pk_abr_profile PRIMARY KEY(`abr_profile_id`)
) COMMENT 'Defines Adaptive Bitrate (ABR) encoding ladder profiles used for multi-platform streaming delivery. Captures profile name, codec (H.264, H.265/HEVC, AV1, VP9), container format (fMP4, TS), rendition count, per-rendition bitrate/resolution/frame-rate specifications, audio codec and channel configuration, HDR/SDR flag, MPEG-DASH or HLS manifest template reference, and target device class. Governs the encoding farm (transcode) output specifications. | Unity Catalog table: media_broadcasting_ecm.distribution.abr_profile';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`playback_session` (
    `playback_session_id` BIGINT COMMENT 'Unique identifier for each individual viewer playback session initiated on the OTT (Over-The-Top) platform. Primary key for the playback session record. | Column playback_session_id (BIGINT) in distribution.playback_session',
    `abr_profile_id` BIGINT COMMENT 'Foreign key linking to distribution.abr_profile. Business justification: Playback sessions should FK to abr_profile master to track which ABR profile was used. Removes abr_profile STRING (derivable from abr_profile.profile_code). | Column abr_profile_id (BIGINT) in distribution.playback_session',
    `app_version_id` BIGINT COMMENT 'Foreign key linking to distribution.app_version. Business justification: Playback sessions should FK to app_version master for version tracking and analytics. Removes app_version STRING (derivable from app_version.version_number). | Column app_version_id (BIGINT) in distribution.playback_session',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: Playback sessions trace to originating facilities for root cause analysis of QoS issues. Essential for facility performance benchmarking and distributed CDN troubleshooting. | Column broadcast_facility_id (BIGINT) in technology.playback_session',
    `sales_campaign_id` BIGINT COMMENT 'Foreign key linking to sales.campaign. Business justification: When playback sessions include ad delivery (dai_enabled), linking to campaign enables campaign reach/frequency measurement, content-adjacency analysis, and cross-domain attribution. Critical for measu | Column campaign_id (BIGINT) in sales.playback_session',
    `closed_caption_record_id` BIGINT COMMENT 'Foreign key linking to compliance.closed_caption_record. Business justification: Individual playback sessions generate closed caption quality metrics (accuracy, synchronization, latency). Session-level caption performance data feeds FCC compliance reporting and quality assurance. | Column closed_caption_record_id (BIGINT) in compliance.playback_session',
    `compliance_consent_record_id` BIGINT COMMENT 'Foreign key linking to compliance.consent_record. Business justification: Playback sessions collect viewing data subject to consent (analytics, personalization, third-party sharing). Session initialization validates consent status before data collection begins. | Column compliance_consent_record_id (BIGINT) in compliance.playback_session',
    `content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: Every playback session must enforce content rating restrictions for parental controls, age-gating, and COPPA compliance. Real-time rating validation during session initialization is standard practice. | Column content_rating_id (BIGINT) in compliance.playback_session',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to audience.demographic_segment. Business justification: Nielsen C3/C7 ratings, GRP/TRP calculation, and programmatic ad targeting require demographic classification of every playback session. Essential for audience guarantee reconciliation and upfront comm | Column demographic_segment_id (BIGINT) in audience.playback_session',
    `drm_policy_id` BIGINT COMMENT 'Foreign key linking to distribution.drm_policy. Business justification: Playback sessions should FK to drm_policy master to track which DRM policy was applied. Removes drm_policy_applied STRING (derivable from drm_policy.policy_code). | Column drm_policy_id (BIGINT) in distribution.playback_session',
    `grant_id` BIGINT COMMENT 'Foreign key linking to rights.rights_grant. Business justification: Playback sessions consume content under specific rights grants. Essential for per-stream royalty calculation, usage reporting to rights holders, and rights compliance verification. Media broadcasting  | Column grant_id (BIGINT) in rights.playback_session',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: DMA attribution is mandatory for Nielsen ratings, local ad insertion, blackout enforcement, and retransmission consent compliance. Every streaming session must be assigned to a market for regulatory a | Column market_coverage_id (BIGINT) in audience.playback_session',
    `media_asset_id` BIGINT COMMENT 'Reference to the content asset being played in this session. Links to the digital asset management system for content metadata and rights verification. | Column media_asset_id (BIGINT) in mediaasset.playback_session',
    `device_type_id` BIGINT COMMENT 'Reference to the device used for this playback session. Enables device-level analytics and QoS (Quality of Service) monitoring. | Column device_device_type_id (BIGINT) in distribution.playback_session',
    `playback_device_type_id` BIGINT COMMENT 'Foreign key linking to distribution.device_type. Business justification: Playback sessions should FK to device_type master for accurate device tracking. Removes device_type STRING (derivable from device_type.device_category). | Column device_type_id (BIGINT) in distribution.playback_session',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Playback sessions on ad-supported platforms generate advertising revenue that must be recognized. Monthly ad revenue reconciliation aggregates sessions by revenue stream for accrual accounting and rev | Column revenue_stream_id (BIGINT) in finance.playback_session',
    `rights_territory_id` BIGINT COMMENT 'Foreign key linking to rights.territory. Business justification: Playback sessions occur in specific territories. Essential for territory-based royalty calculation, rights compliance verification, and exploitation reporting to rights holders. Replaces geographic_co | Column rights_territory_id (BIGINT) in rights.playback_session',
    `streaming_endpoint_id` BIGINT COMMENT 'Foreign key linking to distribution.streaming_endpoint. Business justification: Playback sessions should FK to streaming_endpoint master to track which endpoint served the session. Removes streaming_endpoint_url STRING (derivable from streaming_endpoint.endpoint_url). | Column streaming_endpoint_id (BIGINT) in distribution.playback_session',
    `subscriber_id` BIGINT COMMENT 'Reference to the subscriber who initiated this playback session. Links to the subscriber master record for audience measurement and personalization. | Column subscriber_id (BIGINT) in subscriber.playback_session',
    `tech_incident_id` BIGINT COMMENT 'Foreign key linking to technology.tech_incident. Business justification: Playback sessions are impacted by technology incidents. Required for incident viewer impact assessment and session failure correlation. | Column tech_incident_id (BIGINT) in technology.playback_session',
    `invoice_id` BIGINT COMMENT 'Foreign key linking to billing.invoice. Business justification: Playback sessions for TVOD, rental, and pay-per-view models generate per-transaction invoices. Real business process: transactional VOD billing, rental revenue recognition, PPV event billing. Role pre | Column transaction_invoice_id (BIGINT) in billing.playback_session',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in distribution.playback_session',
    `_source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in distribution.playback_session',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in distribution.playback_session',
    `ad_breaks_served_count` STRING COMMENT 'Number of ad breaks (ad pods) served during this playback session. Used for advertising inventory management and revenue reconciliation. | Column ad_breaks_served_count (INT) in distribution.playback_session',
    `audio_language` STRING COMMENT 'ISO 639 language code for the audio track selected by the viewer. Supports multi-language content analytics and localization strategy. | Column audio_language (STRING) in distribution.playback_session',
    `average_bitrate_kbps` STRING COMMENT 'Average streaming bitrate in kilobits per second during the session. Indicates video quality delivered and network performance. | Column average_bitrate_kbps (INT) in distribution.playback_session',
    `cdn_pop_location` STRING COMMENT 'Geographic location identifier of the CDN point of presence that served this session. Critical for CDN performance optimization and SLA monitoring. | Column cdn_pop_location (STRING) in distribution.playback_session',
    `closed_captions_enabled` BOOLEAN COMMENT 'Indicates whether closed captions were enabled during the session. Critical for accessibility compliance reporting and user preference analysis. | Column closed_captions_enabled (BOOLEAN) in distribution.playback_session',
    `completion_percentage` DECIMAL(18,2) COMMENT 'Percentage of content watched relative to total content duration. Key engagement metric for content performance and recommendation algorithms. | Column completion_percentage (DECIMAL(5,2)) in distribution.playback_session',
    `content_duration_seconds` STRING COMMENT 'Total duration of the content asset in seconds. Used to calculate completion rate and identify partial vs. full viewing sessions. | Column content_duration_seconds (INT) in distribution.playback_session',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.playback_session',
    `dai_enabled` BOOLEAN COMMENT 'Indicates whether Dynamic Ad Insertion was enabled for this playback session. Critical for advertising revenue attribution and campaign measurement. | Column dai_enabled (BOOLEAN) in distribution.playback_session',
    `error_code` STRING COMMENT 'Technical error code if the session ended due to an error. Enables root cause analysis and platform stability monitoring. | Column error_code (STRING) in distribution.playback_session',
    `exit_reason` STRING COMMENT 'The reason the playback session ended. Critical for distinguishing intentional exits from technical failures and optimizing viewer experience. | Column exit_reason (STRING) in distribution.playback_session. Valid values are `user_stop|completion|error|timeout|network_failure|drm_failure`',
    `geographic_city` STRING COMMENT 'City where the viewer is located during playback. Enables hyper-local audience analytics and targeted advertising campaigns. | Column geographic_city (STRING) in distribution.playback_session',
    `geographic_postal_code` STRING COMMENT 'Postal code derived from viewer location. Used for demographic overlay and targeted advertising. Subject to privacy regulations. | Column geographic_postal_code (STRING) in distribution.playback_session',
    `initial_buffering_duration_ms` STRING COMMENT 'Time in milliseconds from session start until playback began. Key QoS metric for measuring time-to-first-frame and viewer experience. | Column initial_buffering_duration_ms (INT) in distribution.playback_session',
    `platform_type` STRING COMMENT 'The platform category on which the playback session occurred. Enables cross-platform measurement and platform-specific QoS analysis. | Column platform_type (STRING) in distribution.playback_session. Valid values are `web|mobile_ios|mobile_android|smart_tv|streaming_device|gaming_console`',
    `playback_mode` STRING COMMENT 'The mode of content consumption: live linear broadcast, VOD (Video On Demand), DVR (time-shifted), or restart. Critical for audience measurement methodology and rights management. | Column playback_mode (STRING) in distribution.playback_session. Valid values are `live|vod|dvr|restart`',
    `rebuffering_events_count` STRING COMMENT 'Number of rebuffering (stalling) events that occurred during the session. Critical QoS metric for viewer experience and churn prediction. | Column rebuffering_events_count (INT) in distribution.playback_session',
    `session_created_timestamp` TIMESTAMP COMMENT 'Timestamp when this playback session record was created in the system. Used for data lineage and operational monitoring. | Column session_created_timestamp (TIMESTAMP) in distribution.playback_session',
    `session_end_timestamp` TIMESTAMP COMMENT 'Precise timestamp when the playback session ended. Used to calculate total watch duration and session completion metrics. | Column session_end_timestamp (TIMESTAMP) in distribution.playback_session',
    `session_start_timestamp` TIMESTAMP COMMENT 'Precise timestamp when the viewer initiated the playback session. Critical for audience measurement, daypart analysis, and concurrent viewer calculations. | Column session_start_timestamp (TIMESTAMP) in distribution.playback_session',
    `session_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this playback session record was last updated. Supports audit trail and data quality monitoring. | Column session_updated_timestamp (TIMESTAMP) in distribution.playback_session',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.playback_session',
    `streaming_protocol` STRING COMMENT 'The ABR (Adaptive Bitrate Streaming) protocol used for content delivery. HLS (HTTP Live Streaming) or MPEG-DASH (Dynamic Adaptive Streaming over HTTP) are most common. | Column streaming_protocol (STRING) in distribution.playback_session. Valid values are `hls|mpeg_dash|smooth_streaming`',
    `subtitle_language` STRING COMMENT 'ISO 639 language code for subtitles displayed during the session. Null if no subtitles were enabled. Supports accessibility and localization analytics. | Column subtitle_language (STRING) in distribution.playback_session',
    `total_ad_duration_seconds` STRING COMMENT 'Cumulative duration of all advertisements served during the session. Essential for advertising billing and viewer experience analysis. | Column total_ad_duration_seconds (INT) in distribution.playback_session',
    `total_rebuffering_duration_ms` STRING COMMENT 'Cumulative time in milliseconds spent in rebuffering state during the session. Complements rebuffering count for comprehensive QoS analysis. | Column total_rebuffering_duration_ms (INT) in distribution.playback_session',
    `total_watch_duration_seconds` STRING COMMENT 'Total time in seconds the viewer actively watched content during this session. Primary metric for audience measurement and content engagement analysis. | Column total_watch_duration_seconds (INT) in distribution.playback_session',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.playback_session',
    `video_resolution` STRING COMMENT 'The video resolution delivered during the session (e.g., 1920x1080, 3840x2160). Indicates quality tier and device capability. | Column video_resolution (STRING) in distribution.playback_session',
    `viewer_ip_address` STRING COMMENT 'IP address of the viewer during the playback session. Used for geographic analysis, fraud detection, and blackout enforcement. Subject to GDPR and CCPA privacy regulations. | Column viewer_ip_address (STRING) in distribution.playback_session',
    CONSTRAINT pk_playback_session PRIMARY KEY(`playback_session_id`)
) COMMENT 'Transactional record of each individual viewer playback session initiated on the OTT platform. Captures session ID, subscriber/device reference, content asset reference, session start and end timestamps, platform and app version, device type, streaming endpoint used, ABR profile, DRM policy applied, initial buffering duration, average bitrate, rebuffering events count, total watch duration, exit reason (user-initiated, error, completion), CDN PoP served, and geographic location. Primary operational event for QoS monitoring and audience measurement. | Unity Catalog table: media_broadcasting_ecm.distribution.playback_session';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`qos_event` (
    `qos_event_id` BIGINT COMMENT 'Unique identifier for the QoS event record. Primary key. | Column qos_event_id (BIGINT) in distribution.qos_event',
    `closed_caption_record_id` BIGINT COMMENT 'Foreign key linking to compliance.closed_caption_record. Business justification: QoS events capture caption-specific failures (caption dropout, synchronization errors, rendering issues). These events are linked to caption compliance records for remediation tracking and regulatory  | Column closed_caption_record_id (BIGINT) in compliance.qos_event',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to audience.demographic_segment. Business justification: QoE analysis by demographic segment identifies service quality disparities, drives platform optimization for key demos, and supports Nielsen commercial ratings validation. Critical for audience guaran | Column demographic_segment_id (BIGINT) in audience.qos_event',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Market-level QoS monitoring supports DMA-specific SLA compliance, identifies regional CDN performance issues, and enables market-based service optimization for distribution partners and Nielsen measur | Column market_coverage_id (BIGINT) in audience.qos_event',
    `noc_alert_id` BIGINT COMMENT 'Foreign key linking to technology.noc_alert. Business justification: QoS events are generated in response to NOC alerts. Required for event correlation analysis and root cause determination. | Column noc_alert_id (BIGINT) in technology.qos_event',
    `playback_session_id` BIGINT COMMENT 'Reference to the parent playback session during which this QoS event occurred. Links to the session-level summary record. | Column playback_session_id (BIGINT) in distribution.qos_event',
    `streaming_endpoint_id` BIGINT COMMENT 'Foreign key linking to distribution.streaming_endpoint. Business justification: QoS events should reference the streaming endpoint for performance tracking. Removes cdn_edge_node STRING (derivable from streaming_endpoint.pop_region). | Column streaming_endpoint_id (BIGINT) in distribution.qos_event',
    `title_id` BIGINT COMMENT 'Unique identifier of the content asset being played during this event. Links to the content catalog for asset-level QoS analysis. | Column title_id (BIGINT) in content.qos_event',
    `transmission_equipment_id` BIGINT COMMENT 'Foreign key linking to technology.transmission_equipment. Business justification: QoS events trace to specific transmission equipment failures. Critical for NOC rapid incident resolution and equipment health monitoring. | Column transmission_equipment_id (BIGINT) in technology.qos_event',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in distribution.qos_event',
    `_source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in distribution.qos_event',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in distribution.qos_event',
    `ad_pod_duration_seconds` STRING COMMENT 'Total duration of the ad pod in seconds when event_type is ad_pod_insertion. Null for other event types. | Column ad_pod_duration_seconds (INT) in distribution.qos_event',
    `ad_pod_position` STRING COMMENT 'Position of the ad pod within the content stream when event_type is ad_pod_insertion. Null for other event types. Used for DAI analysis. | Column ad_pod_position (INT) in distribution.qos_event',
    `bitrate_kbps` STRING COMMENT 'Current streaming bitrate in kilobits per second at the time of the event. Reflects the ABR profile tier active during this event. | Column bitrate_kbps (INT) in distribution.qos_event',
    `buffer_level_seconds` DECIMAL(18,2) COMMENT 'Amount of video content buffered in the player at the time of the event, measured in seconds. Indicates playback health and risk of stalling. | Column buffer_level_seconds (DECIMAL(8,3)) in distribution.qos_event',
    `cdn_cache_status` STRING COMMENT 'CDN cache status for the content segment at the time of the event: hit (served from cache), miss (fetched from origin), stale (expired cache), bypass (cache bypassed). | Column cdn_cache_status (STRING) in distribution.qos_event. Valid values are `hit|miss|stale|bypass`',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.qos_event',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this QoS event record was created in the data platform, in format yyyy-MM-ddTHH:mm:ss.SSSXXX. Used for data lineage and audit purposes. | Column created_timestamp (TIMESTAMP) in distribution.qos_event',
    `device_type` STRING COMMENT 'Type of device on which the playback event occurred: smart TV, mobile phone, tablet, desktop, set-top box, gaming console, etc. | Column device_type (STRING) in distribution.qos_event',
    `download_throughput_kbps` STRING COMMENT 'Measured download throughput in kilobits per second at the time of the event. Used by ABR algorithms to determine optimal bitrate. | Column download_throughput_kbps (INT) in distribution.qos_event',
    `drm_system` STRING COMMENT 'DRM system protecting the content stream: Widevine, FairPlay, PlayReady, or None for unprotected content. | Column drm_system (STRING) in distribution.qos_event. Valid values are `Widevine|FairPlay|PlayReady|None`',
    `dropped_frames_count` STRING COMMENT 'Number of video frames dropped by the player at the time of the event. Indicates rendering performance issues. | Column dropped_frames_count (INT) in distribution.qos_event',
    `error_code` STRING COMMENT 'Specific error code returned by the player or CDN when event_type is error. Null for non-error events. Used for detailed troubleshooting and root-cause analysis. | Column error_code (STRING) in distribution.qos_event',
    `error_message` STRING COMMENT 'Human-readable error message describing the failure when event_type is error. Null for non-error events. | Column error_message (STRING) in distribution.qos_event',
    `event_severity` STRING COMMENT 'Severity level of the QoS event indicating impact on user experience: critical (playback failure), high (significant degradation), medium (noticeable impact), low (minor impact), info (informational only). | Column event_severity (STRING) in distribution.qos_event. Valid values are `critical|high|medium|low|info`',
    `event_timestamp` TIMESTAMP COMMENT 'Precise timestamp when the QoS event occurred during playback, in format yyyy-MM-ddTHH:mm:ss.SSSXXX. | Column event_timestamp (TIMESTAMP) in distribution.qos_event',
    `event_type` STRING COMMENT 'Type of QoS event captured: buffering start/end, bitrate switch (up/down), error code, stall event, seek event, ad pod insertion signal, or heartbeat. [ENUM-REF-CANDIDATE: buffering_start|buffering_end|bitrate_switch_up|bitrate_switch_down|error|stall|seek|ad_pod_insertion|heartbeat — 9 candidates stripped; promote to reference product] | Column event_type (STRING) in distribution.qos_event',
    `geographic_region` STRING COMMENT 'Geographic region or market where the viewer is located at the time of the event. Used for regional QoS analysis and CDN optimization. | Column geographic_region (STRING) in distribution.qos_event',
    `isp_name` STRING COMMENT 'Name of the Internet Service Provider through which the viewer is connected. Used for ISP-level QoS analysis and peering optimization. | Column isp_name (STRING) in distribution.qos_event',
    `network_latency_ms` STRING COMMENT 'Network round-trip latency in milliseconds measured at the time of the event. Indicates network performance and potential delivery issues. | Column network_latency_ms (INT) in distribution.qos_event',
    `new_bitrate_kbps` STRING COMMENT 'Bitrate in kilobits per second after a bitrate switch event. Populated when event_type is bitrate_switch_up or bitrate_switch_down. Null for other event types. | Column new_bitrate_kbps (INT) in distribution.qos_event',
    `origin_server_response_time_ms` STRING COMMENT 'Response time in milliseconds from the origin server when CDN cache status is miss. Null for cache hits. Indicates origin performance. | Column origin_server_response_time_ms (INT) in distribution.qos_event',
    `playback_position_seconds` DECIMAL(18,2) COMMENT 'Current playback position in seconds within the content at the time of the event. Used to correlate events with specific content segments. | Column playback_position_seconds (DECIMAL(12,3)) in distribution.qos_event',
    `player_state` STRING COMMENT 'State of the video player at the time of the event: playing, paused, buffering, seeking, idle, or error. | Column player_state (STRING) in distribution.qos_event. Valid values are `playing|paused|buffering|seeking|idle|error`',
    `player_version` STRING COMMENT 'Version identifier of the video player software that generated this QoS event. Used for player-specific issue analysis. | Column player_version (STRING) in distribution.qos_event',
    `previous_bitrate_kbps` STRING COMMENT 'Bitrate in kilobits per second before a bitrate switch event. Populated when event_type is bitrate_switch_up or bitrate_switch_down. Null for other event types. | Column previous_bitrate_kbps (INT) in distribution.qos_event',
    `seek_position_seconds` DECIMAL(18,2) COMMENT 'Playback position in seconds to which the user seeked. Populated when event_type is seek. Null for other event types. | Column seek_position_seconds (DECIMAL(12,3)) in distribution.qos_event',
    `session_start_timestamp` TIMESTAMP COMMENT 'Timestamp when the parent playback session started, in format yyyy-MM-ddTHH:mm:ss.SSSXXX. Provides temporal context for event sequencing. | Column session_start_timestamp (TIMESTAMP) in distribution.qos_event',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.qos_event',
    `stall_duration_ms` STRING COMMENT 'Duration of the playback stall or buffering event in milliseconds. Populated when event_type is buffering_start, buffering_end, or stall. Null for other event types. | Column stall_duration_ms (INT) in distribution.qos_event',
    `streaming_protocol` STRING COMMENT 'Streaming protocol used for content delivery: HLS (HTTP Live Streaming), MPEG-DASH (Dynamic Adaptive Streaming over HTTP), RTMP, WebRTC, or Smooth Streaming. | Column streaming_protocol (STRING) in distribution.qos_event. Valid values are `HLS|MPEG-DASH|RTMP|WebRTC|Smooth Streaming`',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.qos_event',
    `user_agent` STRING COMMENT 'User agent string of the viewer device and browser/app at the time of the event. Used for device and platform-specific issue analysis. | Column user_agent (STRING) in distribution.qos_event',
    `viewer_ip_address` STRING COMMENT 'IP address of the viewer device at the time of the event. Used for network-level troubleshooting and geographic analysis. May be considered PII in some jurisdictions. | Column viewer_ip_address (STRING) in distribution.qos_event',
    CONSTRAINT pk_qos_event PRIMARY KEY(`qos_event_id`)
) COMMENT 'Granular Quality of Service (QoS) telemetry events captured during playback sessions — distinct from the session-level summary in playback_session. Each record captures a specific QoS signal: buffering start/end, bitrate switch (up/down), error code, stall event, seek event, ad pod insertion signal, or heartbeat. Includes timestamp, session reference, event type, severity, bitrate at event time, buffer level, CDN edge node, and player state. Enables root-cause analysis of streaming quality degradation. | Unity Catalog table: media_broadcasting_ecm.distribution.qos_event';

