CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`sla_performance` (
    `sla_performance_id` BIGINT COMMENT 'Unique identifier for the SLA performance measurement record. | Column sla_performance_id (BIGINT) in distribution.sla_performance',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: SLA measurements are facility-specific for uptime and latency reporting. Required for facility-level SLA compliance reporting and vendor performance reviews. | Column broadcast_facility_id (BIGINT) in technology.sla_performance',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: SLA measurement is market-specific due to CDN topology, regional infrastructure differences, and DMA-level service commitments in distribution partner agreements. Required for carriage fee penalty cal | Column market_coverage_id (BIGINT) in audience.sla_performance',
    `credit_memo_id` BIGINT COMMENT 'Foreign key linking to billing.credit_memo. Business justification: SLA breaches trigger contractual penalties and service credits to distribution partners or advertisers. Real business process: SLA penalty assessment, makegood credit issuance, partner compensation fo | Column penalty_credit_memo_id (BIGINT) in billing.sla_performance',
    `sla_definition_id` BIGINT COMMENT 'Reference to the SLA definition that establishes the target thresholds and measurement criteria for this performance record. | Column sla_definition_id (BIGINT) in distribution.sla_performance',
    `tech_incident_id` BIGINT COMMENT 'The identifier of the incident management ticket or case associated with this SLA breach. Links to operational incident tracking systems. | Column tech_incident_id (BIGINT) in technology.sla_performance',
