    `carriage_fee_amount` DECIMAL(18,2) COMMENT 'Monetary compensation paid by the distribution partner to the content provider for the right to carry the channel or content package. May be per-subscriber, flat fee, or tiered based on subscriber count. | Column carriage_fee_amount (DECIMAL(15,2)) in distribution.carriage_agreement',
    `carriage_fee_currency` STRING COMMENT 'Three-letter ISO 4217 currency code for the carriage fee amount (e.g., USD, GBP, EUR). | Column carriage_fee_currency (STRING) in distribution.carriage_agreement. Valid values are `^[A-Z]{3}$`',
    `carriage_fee_structure` STRING COMMENT 'Pricing model for the carriage fee: per-subscriber (fee per active subscriber), flat monthly (fixed monthly payment), tiered (rate varies by subscriber volume), revenue share (percentage of ad or subscription revenue), or barter (non-cash compensation such as promotional commitments or channel positioning). | Column carriage_fee_structure (STRING) in distribution.carriage_agreement. Valid values are `per_subscriber|flat_monthly|tiered|revenue_share|barter`',
    `channel_number_assignment` STRING COMMENT 'The channel number or dial position assigned to the channel on the distribution platform. May vary by market or headend. | Column channel_number_assignment (STRING) in distribution.carriage_agreement',
    `channel_positioning_tier` STRING COMMENT 'The service tier or package in which the channel is positioned (e.g., basic, expanded basic, premium, sports tier). Affects channel visibility and subscriber reach. | Column channel_positioning_tier (STRING) in distribution.carriage_agreement',
    `compensation_terms` STRING COMMENT 'Detailed description of all compensation provided under the agreement, including cash payments, barter arrangements (e.g., promotional commitments, ad inventory exchange), channel carriage reciprocity, or other non-monetary considerations. | Column compensation_terms (STRING) in distribution.carriage_agreement',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.carriage_agreement',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this carriage agreement record was first created in the system. | Column created_timestamp (TIMESTAMP) in distribution.carriage_agreement',
    `dispute_resolution_mechanism` STRING COMMENT 'Agreed method for resolving disputes arising under the agreement: arbitration (binding third-party decision), mediation (facilitated negotiation), litigation (court proceedings), or negotiation (direct party-to-party resolution). | Column dispute_resolution_mechanism (STRING) in distribution.carriage_agreement. Valid values are `arbitration|mediation|litigation|negotiation`',
    `drm_requirements` STRING COMMENT 'DRM and content protection requirements mandated under the agreement, such as encryption standards, conditional access systems, watermarking, and anti-piracy measures. | Column drm_requirements (STRING) in distribution.carriage_agreement',
    `effective_date` DATE COMMENT 'Date when the carriage agreement becomes binding and the distribution partner is authorized to carry the channel or content package. | Column effective_date (DATE) in distribution.carriage_agreement',
    `exclusivity_window` STRING COMMENT 'Period during which the distribution partner has exclusive carriage rights within a defined geographic territory or platform category (e.g., exclusive MVPD rights in a DMA, exclusive vMVPD rights nationally). | Column exclusivity_window (STRING) in distribution.carriage_agreement',
    `expiration_date` DATE COMMENT 'Date when the carriage agreement term ends. Nullable for open-ended or evergreen agreements subject to termination notice. | Column expiration_date (DATE) in distribution.carriage_agreement',
    `geographic_coverage` STRING COMMENT 'Geographic scope of the carriage agreement, typically expressed as authorized DMAs (Designated Market Areas), states, regions, or national coverage. Defines where the distribution partner is authorized to carry the content. | Column geographic_coverage (STRING) in distribution.carriage_agreement',
    `governing_law_jurisdiction` STRING COMMENT 'Legal jurisdiction and governing law applicable to the agreement (e.g., State of New York, England and Wales). Determines which courts and laws apply in case of dispute. | Column governing_law_jurisdiction (STRING) in distribution.carriage_agreement',
    `holdback_restrictions` STRING COMMENT 'Restrictions on when or where content may be made available on other platforms or windows. Protects the distribution partners investment by limiting competing distribution during the agreement term. | Column holdback_restrictions (STRING) in distribution.carriage_agreement',
    `last_amendment_date` DATE COMMENT 'Date of the most recent amendment or modification to the carriage agreement. | Column last_amendment_date (DATE) in distribution.carriage_agreement',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this carriage agreement record was last updated in the system. | Column last_modified_timestamp (TIMESTAMP) in distribution.carriage_agreement',
    `minimum_subscriber_guarantee` STRING COMMENT 'Minimum number of subscribers the distribution partner guarantees to deliver for the channel. Used in per-subscriber fee calculations and performance commitments. | Column minimum_subscriber_guarantee (INT) in distribution.carriage_agreement',
    `must_carry_election` BOOLEAN COMMENT 'Indicates whether the broadcaster has elected must-carry status under FCC rules, requiring the MVPD to carry the signal without negotiation. Applicable to qualified broadcast stations. | Column must_carry_election (BOOLEAN) in distribution.carriage_agreement',
    `negotiation_history` STRING COMMENT 'Summary of key negotiation milestones, amendments, and material changes to the agreement over its lifecycle. Provides context for current terms and future renegotiations. | Column negotiation_history (STRING) in distribution.carriage_agreement',
    `promotional_commitment` STRING COMMENT 'Marketing and promotional obligations agreed by either party, such as on-air promotion, co-marketing campaigns, EPG placement guarantees, or cross-platform promotion. | Column promotional_commitment (STRING) in distribution.carriage_agreement',
    `renewal_terms` STRING COMMENT 'Conditions and terms governing agreement renewal, including renewal period length, rate adjustments, renegotiation triggers, and notice requirements. | Column renewal_terms (STRING) in distribution.carriage_agreement',
    `retransmission_consent_granted` BOOLEAN COMMENT 'Indicates whether retransmission consent has been granted under FCC regulations, authorizing the MVPD to rebroadcast over-the-air signals. Applicable only to retransmission consent agreement types. | Column retransmission_consent_granted (BOOLEAN) in distribution.carriage_agreement',
    `service_level_agreement` STRING COMMENT 'Performance commitments and service quality standards, including uptime guarantees, signal quality metrics, fault resolution times, and penalties for non-compliance. | Column service_level_agreement (STRING) in distribution.carriage_agreement',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.carriage_agreement',
    `technical_delivery_requirements` STRING COMMENT 'Technical specifications for content delivery, including signal format (HD, 4K, HDR), encoding standards (MPEG-2, MPEG-4, HEVC), delivery method (satellite, fiber, IP), and quality parameters (bitrate, resolution, audio channels). | Column technical_delivery_requirements (STRING) in distribution.carriage_agreement',
    `termination_notice_days` STRING COMMENT 'Number of days advance notice required by either party to terminate the agreement. Protects both parties from abrupt service disruption. | Column termination_notice_days (INT) in distribution.carriage_agreement',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.carriage_agreement',
    CONSTRAINT pk_carriage_agreement PRIMARY KEY(`carriage_agreement_id`)
) COMMENT 'Contractual record governing the terms under which a channel or content package is carried by an MVPD, vMVPD, or OTT platform. Covers both retransmission consent agreements (FCC-regulated authorization for MVPDs to rebroadcast OTA signals) and standard carriage contracts. Captures agreement type (retransmission consent, must-carry, voluntary carriage), retransmission consent terms, must-carry election status, carriage fee rates, channel positioning tiers, geographic coverage (authorized DMAs), exclusivity windows, holdback restrictions, compensation terms (cash, channel carriage, promotional commitments), contract effective/expiry dates, and negotiation history. Links to distribution partner and channel master. Distinct from rights licensing contracts owned by the rights domain. | Unity Catalog table: media_broadcasting_ecm.distribution.carriage_agreement';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`distribution_carriage_fee_invoice` (
    `distribution_carriage_fee_invoice_id` BIGINT COMMENT 'Unique identifier for the carriage fee invoice record. Primary key for this transactional billing entity. | Column distribution_carriage_fee_invoice_id (BIGINT) in distribution.distribution_carriage_fee_invoice',
    `accounts_receivable_id` BIGINT COMMENT 'Foreign key linking to finance.accounts_receivable. Business justification: Carriage fee invoices create A/R entries when billed to distribution partners. Monthly A/R aging reports include outstanding carriage fee invoices for cash flow management and collections tracking in  | Column accounts_receivable_id (BIGINT) in finance.distribution_carriage_fee_invoice',
    `billing_carriage_fee_invoice_id` BIGINT COMMENT 'FK to canonical billing carriage fee invoice | Column billing_carriage_fee_invoice_id (BIGINT) in billing.distribution_carriage_fee_invoice',
    `carriage_agreement_id` BIGINT COMMENT 'Reference to the master carriage agreement under which this invoice is issued. Links to the contractual relationship governing carriage fees. | Column carriage_agreement_id (BIGINT) in distribution.distribution_carriage_fee_invoice',
    `distribution_partner_id` BIGINT COMMENT 'Reference to the MVPD, vMVPD, cable operator, or OTT platform partner who is the counterparty to this invoice. The party being billed or paying the carriage fee. | Column distribution_partner_id (BIGINT) in distribution.distribution_carriage_fee_invoice',
    `rep_id` BIGINT COMMENT 'Foreign key linking to sales.rep. Business justification: Carriage fee invoices are tracked by responsible sales rep for commission calculation and dispute resolution. Essential for rep compensation on recurring carriage revenue, account health monitoring, a | Column responsible_sales_rep_id (BIGINT) in sales.distribution_carriage_fee_invoice',
    `revenue_recognition_event_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_recognition_event. Business justification: Carriage fee invoices trigger revenue recognition events under ASC 606/IFRS 15. Monthly revenue recognition close ties invoices to recognition events for financial statement preparation and revenue as | Column revenue_recognition_event_id (BIGINT) in finance.distribution_carriage_fee_invoice',
    `subscriber_count_report_id` BIGINT COMMENT 'Foreign key linking to distribution.subscriber_count_report. Business justification: Carriage fee invoices are based on subscriber count reports. Billing uses reported subscriber counts for fee calculation. Removes subscriber_count BIGINT (derivable from subscriber_count_report.report | Column subscriber_count_report_id (BIGINT) in distribution.distribution_carriage_fee_invoice',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in distribution.distribution_carriage_fee_invoice',
    `_source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in distribution.distribution_carriage_fee_invoice',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in distribution.distribution_carriage_fee_invoice',
    `adjustment_amount` DECIMAL(18,2) COMMENT 'Total adjustments applied to the base fee, including discounts, credits, penalties, or promotional adjustments. May be positive or negative. | Column adjustment_amount (DECIMAL(18,2)) in distribution.distribution_carriage_fee_invoice',
    `base_fee_amount` DECIMAL(18,2) COMMENT 'The base carriage fee amount before any adjustments, discounts, or taxes. Represents the core contractual fee for the billing period. | Column base_fee_amount (DECIMAL(18,2)) in distribution.distribution_carriage_fee_invoice',
    `billing_period_end_date` DATE COMMENT 'The last date of the period for which carriage fees are being billed. Defines the end of the service or subscription window covered by this invoice. | Column billing_period_end_date (DATE) in distribution.distribution_carriage_fee_invoice',
    `billing_period_start_date` DATE COMMENT 'The first date of the period for which carriage fees are being billed. Defines the beginning of the service or subscription window covered by this invoice. | Column billing_period_start_date (DATE) in distribution.distribution_carriage_fee_invoice',
    `cost_center_code` STRING COMMENT 'The cost center or profit center to which this invoice is allocated for internal financial reporting and management accounting. | Column cost_center_code (STRING) in distribution.distribution_carriage_fee_invoice',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.distribution_carriage_fee_invoice',
    `created_by_user` STRING COMMENT 'The username or identifier of the user or system process that created this invoice record. Used for audit and accountability. | Column created_by_user (STRING) in distribution.distribution_carriage_fee_invoice',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this invoice record was first created in the system. Used for audit trail and data lineage. | Column created_timestamp (TIMESTAMP) in distribution.distribution_carriage_fee_invoice',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code indicating the currency in which the invoice is denominated (e.g., USD, EUR, GBP). | Column currency_code (STRING) in distribution.distribution_carriage_fee_invoice. Valid values are `^[A-Z]{3}$`',
    `dispute_date` DATE COMMENT 'The date on which the dispute was formally raised by the distribution partner. Null if the invoice has never been disputed. | Column dispute_date (DATE) in distribution.distribution_carriage_fee_invoice',
    `dispute_flag` BOOLEAN COMMENT 'Boolean indicator of whether the invoice is currently under dispute by the distribution partner. True if disputed, false otherwise. | Column dispute_flag (BOOLEAN) in distribution.distribution_carriage_fee_invoice',
    `dispute_reason` STRING COMMENT 'Free-text description of the reason for the dispute, if the invoice is disputed. Captures the distribution partners objection or concern. | Column dispute_reason (STRING) in distribution.distribution_carriage_fee_invoice',
    `due_date` DATE COMMENT 'The date by which payment is contractually required. Used to determine overdue status and trigger late payment processes. | Column due_date (DATE) in distribution.distribution_carriage_fee_invoice',
    `fee_basis` STRING COMMENT 'The pricing model or calculation method used to determine the carriage fee amount. Defines whether the fee is per-subscriber, flat-rate, tiered by volume, revenue-share, or a hybrid structure. | Column fee_basis (STRING) in distribution.distribution_carriage_fee_invoice. Valid values are `per_subscriber|flat_rate|tiered|revenue_share|hybrid|minimum_guarantee`',
    `general_ledger_account_code` STRING COMMENT 'The GL account code to which this carriage fee invoice is posted in the financial system. Used for financial reporting and revenue recognition. | Column general_ledger_account_code (STRING) in distribution.distribution_carriage_fee_invoice',
    `invoice_date` DATE COMMENT 'The date on which the invoice was officially issued to the distribution partner. This is the principal business event timestamp for the invoice transaction. | Column invoice_date (DATE) in distribution.distribution_carriage_fee_invoice',
    `invoice_number` STRING COMMENT 'Externally-visible unique invoice number used for billing correspondence, payment reconciliation, and financial reporting. Typically follows a sequential or structured numbering scheme. | Column invoice_number (STRING) in distribution.distribution_carriage_fee_invoice',
    `invoice_status` STRING COMMENT 'Current lifecycle status of the carriage fee invoice. Tracks progression from draft through issuance, acknowledgment, payment, and potential dispute or cancellation. [ENUM-REF-CANDIDATE: draft|issued|sent|acknowledged|paid|partially_paid|overdue|disputed|cancelled|void — 10 candidates stripped; promote to reference product] | Column invoice_status (STRING) in distribution.distribution_carriage_fee_invoice',
    `notes` STRING COMMENT 'Free-text notes or comments related to the invoice. May include special instructions, explanations of adjustments, or internal remarks. | Column notes (STRING) in distribution.distribution_carriage_fee_invoice',
    `payment_method` STRING COMMENT 'The payment instrument or mechanism used or expected for settling this invoice (e.g., wire transfer, ACH, check). | Column payment_method (STRING) in distribution.distribution_carriage_fee_invoice. Valid values are `wire_transfer|ach|check|credit_card|direct_debit|other`',
    `payment_received_date` DATE COMMENT 'The date on which payment was received and applied to this invoice. Null if the invoice has not been paid. | Column payment_received_date (DATE) in distribution.distribution_carriage_fee_invoice',
    `payment_reference_number` STRING COMMENT 'External reference number or transaction identifier provided by the payer or payment processor. Used for payment reconciliation and traceability. | Column payment_reference_number (STRING) in distribution.distribution_carriage_fee_invoice',
    `payment_status` STRING COMMENT 'Current payment status of the invoice. Tracks whether the invoice has been paid in full, partially paid, remains unpaid, or is overdue or disputed. | Column payment_status (STRING) in distribution.distribution_carriage_fee_invoice. Valid values are `unpaid|paid|partially_paid|overdue|disputed|waived`',
    `payment_terms` STRING COMMENT 'Contractual payment terms for this invoice, such as Net 30, Net 60, or custom terms. Defines the expected payment timeline and conditions. | Column payment_terms (STRING) in distribution.distribution_carriage_fee_invoice',
    `reconciliation_date` DATE COMMENT 'The date on which the invoice was successfully reconciled against subscriber data, payments, and contractual obligations. Null if reconciliation is pending or failed. | Column reconciliation_date (DATE) in distribution.distribution_carriage_fee_invoice',
    `reconciliation_status` STRING COMMENT 'Status of the revenue assurance reconciliation process for this invoice. Indicates whether the invoice has been matched to subscriber reports, payments, and contractual terms. | Column reconciliation_status (STRING) in distribution.distribution_carriage_fee_invoice. Valid values are `pending|reconciled|discrepancy|under_review`',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.distribution_carriage_fee_invoice',
    `tax_amount` DECIMAL(18,2) COMMENT 'Total tax amount applied to the invoice, including sales tax, VAT, or other applicable taxes based on jurisdiction and tax rules. | Column tax_amount (DECIMAL(18,2)) in distribution.distribution_carriage_fee_invoice',
    `total_amount` DECIMAL(18,2) COMMENT 'The final total amount due on the invoice, calculated as base fee plus adjustments plus taxes. This is the amount the distribution partner must pay. | Column total_amount (DECIMAL(18,2)) in distribution.distribution_carriage_fee_invoice',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.distribution_carriage_fee_invoice',
    `updated_by_user` STRING COMMENT 'The username or identifier of the user or system process that last modified this invoice record. Used for audit and accountability. | Column updated_by_user (STRING) in distribution.distribution_carriage_fee_invoice',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this invoice record was last modified. Used for audit trail and change tracking. | Column updated_timestamp (TIMESTAMP) in distribution.distribution_carriage_fee_invoice',
    CONSTRAINT pk_distribution_carriage_fee_invoice PRIMARY KEY(`distribution_carriage_fee_invoice_id`)
) COMMENT 'Transactional billing record for carriage fees owed by or to distribution partners under active carriage agreements. Captures invoice period, fee amount, fee basis (per-subscriber, flat-rate, tiered), currency, payment due date, payment status, and reconciliation flags. Supports revenue assurance and financial reconciliation processes. Distinct from subscriber invoices (owned by billing domain) and advertising invoices (owned by advertising domain). | Unity Catalog table: media_broadcasting_ecm.distribution.distribution_carriage_fee_invoice';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`delivery_channel` (
    `delivery_channel_id` BIGINT COMMENT 'Unique identifier for the delivery channel. Primary key. | Column delivery_channel_id (BIGINT) in distribution.delivery_channel',
