    `concurrent_stream_limit` STRING COMMENT 'The maximum number of simultaneous streams allowed per user account or license. | Column concurrent_stream_limit (INT) in distribution.drm_policy',
    `content_key_reference` STRING COMMENT 'The unique identifier for the encryption key used to protect the content. | Column content_key_reference (STRING) in distribution.drm_policy',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.drm_policy',
