    `effective_end_date` DATE COMMENT 'The date when this DRM policy expires or is no longer enforceable. Null indicates indefinite validity. | Column effective_end_date (DATE) in distribution.drm_policy',
    `effective_start_date` DATE COMMENT 'The date when this DRM policy becomes active and enforceable for content protection. | Column effective_start_date (DATE) in distribution.drm_policy',
    `encryption_scheme` STRING COMMENT 'The encryption scheme used for content protection (CENC, CBC1, CENS, CBCS) as defined by Common Encryption standards. | Column encryption_scheme (STRING) in distribution.drm_policy. Valid values are `cenc|cbc1|cens|cbcs`',
    `geo_restriction_enabled` BOOLEAN COMMENT 'Flag indicating whether geographic restrictions are enforced for content delivery based on viewer location. | Column geo_restriction_enabled (BOOLEAN) in distribution.drm_policy',
    `hdcp_level_required` STRING COMMENT 'The minimum HDCP version required for output protection to prevent unauthorized digital copying. [ENUM-REF-CANDIDATE: none|hdcp_1_0|hdcp_1_1|hdcp_1_2|hdcp_1_3|hdcp_1_4|hdcp_2_0|hdcp_2_1|hdcp_2_2|hdcp_2_3 — 10 candidates stripped; promote to reference product] | Column hdcp_level_required (STRING) in distribution.drm_policy',
    `key_rotation_interval_hours` STRING COMMENT 'The frequency in hours at which encryption keys are rotated for enhanced security. | Column key_rotation_interval_hours (INT) in distribution.drm_policy',
    `license_duration_seconds` STRING COMMENT 'The validity period in seconds for a DRM license before it must be renewed. | Column license_duration_seconds (INT) in distribution.drm_policy',
    `license_server_endpoint` STRING COMMENT 'The URL endpoint of the DRM license server that issues decryption keys to authorized clients. | Column license_server_endpoint (STRING) in distribution.drm_policy',
    `max_device_registrations` STRING COMMENT 'The maximum number of devices that can be registered for content playback per user account. | Column max_device_registrations (INT) in distribution.drm_policy',
    `offline_license_duration_hours` STRING COMMENT 'The maximum duration in hours that offline downloaded content remains playable before license expiration. | Column offline_license_duration_hours (INT) in distribution.drm_policy',
    `offline_playback_enabled` BOOLEAN COMMENT 'Flag indicating whether content can be downloaded and played offline without an active internet connection. | Column offline_playback_enabled (BOOLEAN) in distribution.drm_policy',
    `offline_playback_window_hours` STRING COMMENT 'The time window in hours during which offline content must be played once playback begins. | Column offline_playback_window_hours (INT) in distribution.drm_policy',
    `persistent_license_enabled` BOOLEAN COMMENT 'Flag indicating whether licenses can be stored persistently on the device for offline or repeated playback. | Column persistent_license_enabled (BOOLEAN) in distribution.drm_policy',
    `playback_duration_hours` STRING COMMENT 'The time window in hours during which content must be consumed once playback begins for rental content. | Column playback_duration_hours (INT) in distribution.drm_policy',
    `policy_code` STRING COMMENT 'Unique business code or identifier for the DRM policy used across systems and platforms. | Column policy_code (STRING) in distribution.drm_policy',
    `policy_name` STRING COMMENT 'Human-readable name of the DRM policy for identification and reference purposes. | Column policy_name (STRING) in distribution.drm_policy',
    `policy_priority` STRING COMMENT 'The priority ranking of this policy when multiple policies could apply. Lower numbers indicate higher priority. | Column policy_priority (INT) in distribution.drm_policy',
    `policy_status` STRING COMMENT 'The current lifecycle status of the DRM policy (draft, active, suspended, deprecated, retired). | Column policy_status (STRING) in distribution.drm_policy. Valid values are `draft|active|suspended|deprecated|retired`',
    `rental_duration_hours` STRING COMMENT 'The total rental period in hours during which content is accessible for Transactional Video On Demand (TVOD) rentals. | Column rental_duration_hours (INT) in distribution.drm_policy',
    `screen_capture_blocked` BOOLEAN COMMENT 'Flag indicating whether screen capture and recording are blocked during content playback. | Column screen_capture_blocked (BOOLEAN) in distribution.drm_policy',
    `security_level` STRING COMMENT 'The security level required for DRM implementation (software or hardware-based cryptography and decoding). | Column security_level (STRING) in distribution.drm_policy. Valid values are `sw_secure_crypto|sw_secure_decode|hw_secure_crypto|hw_secure_decode|hw_secure_all`',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.drm_policy',
    `token_expiry_seconds` STRING COMMENT 'The expiration time in seconds for authentication tokens used in DRM license acquisition. | Column token_expiry_seconds (INT) in distribution.drm_policy',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.drm_policy',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this DRM policy record was last modified. | Column updated_timestamp (TIMESTAMP) in distribution.drm_policy',
    `widevine_security_level` STRING COMMENT 'The Widevine-specific security level (L1 hardware-backed, L2 software-backed, L3 software only). | Column widevine_security_level (STRING) in distribution.drm_policy. Valid values are `L1|L2|L3`',
