    CONSTRAINT pk_drm_policy PRIMARY KEY(`drm_policy_id`)
) COMMENT 'Reference master defining Digital Rights Management packaging and enforcement policies applied to content streams. Captures DRM system (Widevine, PlayReady, FairPlay), license server endpoint, key rotation interval, output control rules (HDCP level, analog sunset), geo-restriction enforcement flag, offline download permissions, concurrent stream limits, and token expiry settings. Governs how content is protected during OTT and MVPD delivery. | Unity Catalog table: media_broadcasting_ecm.distribution.drm_policy';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`cdn_configuration` (
