    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.delivery_sla',
    `uptime_commitment_percent` DECIMAL(18,2) COMMENT 'Guaranteed uptime percentage for content delivery availability (e.g., 99.95% uptime commitment). | Column uptime_commitment_percent (DECIMAL(5,2)) in distribution.delivery_sla',
