    `rental_price` DECIMAL(18,2) COMMENT 'Price charged to viewers for transactional rental access during this window (TVOD model). Nullable if not applicable. | Column rental_price (DECIMAL(10,2)) in distribution.release_window',
    `revenue_share_percent` DECIMAL(18,2) COMMENT 'Percentage of revenue shared with the platform or distributor for this window, per the commercial distribution agreement. | Column revenue_share_percent (DECIMAL(5,2)) in distribution.release_window',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.release_window',
    `streaming_protocol` STRING COMMENT 'Primary streaming protocol used for content delivery in this window. HLS = HTTP Live Streaming; MPEG-DASH = Dynamic Adaptive Streaming over HTTP; Smooth Streaming = Microsoft Smooth Streaming; RTMP = Real-Time Messaging Protocol; Progressive Download = traditional file download. | Column streaming_protocol (STRING) in distribution.release_window. Valid values are `hls|mpeg_dash|smooth_streaming|rtmp|progressive_download`',
    `subtitle_languages` STRING COMMENT 'Comma-separated list of subtitle languages available for this distribution window (ISO 639-1 codes). | Column subtitle_languages (STRING) in distribution.release_window',
