    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.release_window',
    `window_close_date` DATE COMMENT 'Date when the distribution window closes and content is no longer available on the specified platform or channel. Nullable for open-ended windows. | Column window_close_date (DATE) in distribution.release_window',
