    `cdn_node_code` STRING COMMENT 'Identifier of the CDN edge node that served the content for this delivery event. | Column cdn_node_code (STRING) in distribution.delivery_event',
    `cdn_pop_location` STRING COMMENT 'Geographic location identifier of the CDN point of presence that served this delivery. | Column cdn_pop_location (STRING) in distribution.delivery_event',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.delivery_event',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this delivery event record was created in the system. | Column created_timestamp (TIMESTAMP) in distribution.delivery_event',
    `dai_enabled` BOOLEAN COMMENT 'Flag indicating whether dynamic ad insertion was enabled for this delivery event. | Column dai_enabled (BOOLEAN) in distribution.delivery_event',
    `delivery_channel_type` STRING COMMENT 'Classification of the delivery channel type (linear broadcast, OTT streaming, VOD, FAST channel, MVPD, vMVPD). | Column delivery_channel_type (STRING) in distribution.delivery_event. Valid values are `linear_broadcast|ott_streaming|vod|fast_channel|mvpd|vmvpd`',
    `delivery_status` STRING COMMENT 'Outcome status of the delivery event (success, failure, degraded quality, partial delivery). | Column delivery_status (STRING) in distribution.delivery_event. Valid values are `success|failure|degraded|partial`',
    `delivery_technology` STRING COMMENT 'Technical protocol or standard used for content delivery (HLS, MPEG-DASH, DVB, ATSC, QAM, Smooth Streaming, RTMP). [ENUM-REF-CANDIDATE: hls|mpeg_dash|dvb|atsc|qam|smooth_streaming|rtmp — 7 candidates stripped; promote to reference product] | Column delivery_technology (STRING) in distribution.delivery_event',
    `drm_system` STRING COMMENT 'DRM system applied to protect the content during delivery (Widevine, PlayReady, FairPlay, or none for unprotected content). | Column drm_system (STRING) in distribution.delivery_event. Valid values are `widevine|playready|fairplay|none`',
    `error_code` STRING COMMENT 'System error code if the delivery event encountered a failure or degradation. | Column error_code (STRING) in distribution.delivery_event',
    `error_message` STRING COMMENT 'Human-readable error message describing the delivery failure or issue. | Column error_message (STRING) in distribution.delivery_event',
    `event_timestamp` TIMESTAMP COMMENT 'Precise timestamp when the delivery event occurred (stream start, broadcast transmission, VOD delivery initiation). | Column event_timestamp (TIMESTAMP) in distribution.delivery_event',
    `event_type` STRING COMMENT 'Type of delivery event being recorded (stream start, VOD delivery, broadcast transmission, DAI insertion, stream end, playback error, buffer event). [ENUM-REF-CANDIDATE: stream_start|vod_delivery|broadcast_tx|dai_insertion|stream_end|playback_error|buffer_event — 7 candidates stripped; promote to reference product] | Column event_type (STRING) in distribution.delivery_event',
    `geographic_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code where the delivery occurred (e.g., USA, GBR, CAN). | Column geographic_country_code (STRING) in distribution.delivery_event',
    `geographic_region` STRING COMMENT 'Geographic region where the content was delivered (e.g., North America, EMEA, APAC, or specific country/state codes). | Column geographic_region (STRING) in distribution.delivery_event',
    `network_latency_ms` STRING COMMENT 'Network latency measured in milliseconds between CDN edge and viewer device. | Column network_latency_ms (INT) in distribution.delivery_event',
    `origin_server_response_time_ms` STRING COMMENT 'Response time from origin server in milliseconds for cache-miss scenarios. | Column origin_server_response_time_ms (INT) in distribution.delivery_event',
    `resolution` STRING COMMENT 'Video resolution delivered (e.g., 1920x1080, 3840x2160, 1280x720). | Column resolution (STRING) in distribution.delivery_event',
    `scte35_signal_type` STRING COMMENT 'Type of SCTE-35 signal that triggered the DAI event (e.g., splice_insert, time_signal). | Column scte35_signal_type (STRING) in distribution.delivery_event',
    `session_duration_seconds` STRING COMMENT 'Total duration of the delivery session in seconds for streaming events. | Column session_duration_seconds (INT) in distribution.delivery_event',
    `sla_tier` STRING COMMENT 'SLA tier classification applicable to this delivery event (e.g., premium, standard, basic). | Column sla_tier (STRING) in distribution.delivery_event',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.delivery_event',
    `streaming_protocol` STRING COMMENT 'Specific streaming protocol used for OTT delivery (HLS, DASH, Smooth Streaming, RTMP, WebRTC). | Column streaming_protocol (STRING) in distribution.delivery_event. Valid values are `hls|dash|smooth|rtmp|webrtc`',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.delivery_event',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this delivery event record was last updated. | Column updated_timestamp (TIMESTAMP) in distribution.delivery_event',
    `user_agent` STRING COMMENT 'User agent string from the viewer device identifying browser/app and operating system. | Column user_agent (STRING) in distribution.delivery_event',
    `video_codec` STRING COMMENT 'Video codec used for encoding the delivered content (e.g., H.264, H.265/HEVC, VP9, AV1). | Column video_codec (STRING) in distribution.delivery_event',
    `viewer_ip_address` STRING COMMENT 'IP address of the viewer device that received the content delivery. | Column viewer_ip_address (STRING) in distribution.delivery_event',
    CONSTRAINT pk_delivery_event PRIMARY KEY(`delivery_event_id`)
) COMMENT 'Transactional record capturing each discrete content delivery event — including stream session initiations, linear broadcast transmissions, VOD asset deliveries, FAST channel playout events, and dynamic ad insertion (DAI) sessions. Captures event timestamp, event type (stream_start, vod_delivery, broadcast_tx, dai_insertion), delivery channel, content asset reference, delivery technology (HLS, MPEG-DASH, DVB, ATSC), CDN node, geographic region, stream quality (bitrate, resolution), delivery status (success, failure, degraded), error codes, and DAI-specific attributes (ad pod position, SCTE-35 signal, fill rate) where applicable. Feeds delivery SLA monitoring, CDN performance reporting, and AVOD/FAST monetization reconciliation. | Unity Catalog table: media_broadcasting_ecm.distribution.delivery_event';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`sla_breach` (
    `sla_breach_id` BIGINT COMMENT 'Unique identifier for the SLA breach record. Primary key for the sla_breach product. | Column sla_breach_id (BIGINT) in distribution.sla_breach',
    `accounts_payable_id` BIGINT COMMENT 'Foreign key linking to finance.accounts_payable. Business justification: SLA breaches with distribution partners trigger penalty payments or makegood obligations, creating A/P liabilities. Quarterly SLA review creates A/P accruals for penalties owed to partners per carriag | Column accounts_payable_id (BIGINT) in finance.sla_breach',
    `incident_id` BIGINT COMMENT 'Foreign key linking to compliance.incident. Business justification: SLA breaches violating regulatory commitments (accessibility uptime, emergency alert delivery, closed caption availability) escalate to compliance incidents. Breach severity and regulatory impact dete | Column compliance_incident_id (BIGINT) in compliance.sla_breach',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: SLA breaches require incident ownership for root cause analysis, remediation coordination, partner communication, and penalty mitigation. Essential for on-call rotations, incident postmortems, perform | Column incident_owner_employee_id (BIGINT) in workforce.sla_breach',
    `noc_alert_id` BIGINT COMMENT 'Foreign key linking to technology.noc_alert. Business justification: SLA breaches are triggered by NOC alerts. Required for breach root cause analysis and penalty dispute resolution traceability. | Column noc_alert_id (BIGINT) in technology.sla_breach',
    `sla_definition_id` BIGINT COMMENT 'Reference to the SLA definition that was breached, linking to the specific SLA commitment and thresholds. | Column sla_definition_id (BIGINT) in distribution.sla_breach',
    `streaming_endpoint_id` BIGINT COMMENT 'Reference to the streaming endpoint where the breach occurred, identifying the specific delivery channel affected. | Column streaming_endpoint_id (BIGINT) in distribution.sla_breach',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in distribution.sla_breach',
    `_source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in distribution.sla_breach',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in distribution.sla_breach',
    `affected_platform` STRING COMMENT 'The distribution platform or service tier affected by the breach, such as OTT, MVPD, or FAST channel. | Column affected_platform (STRING) in distribution.sla_breach',
    `affected_region` STRING COMMENT 'The geographic region or CDN Point of Presence (POP) where the breach occurred, identifying the scope of impact. | Column affected_region (STRING) in distribution.sla_breach',
    `breach_duration_minutes` STRING COMMENT 'The total duration of the SLA breach in minutes, from detection to restoration of service within SLA parameters. | Column breach_duration_minutes (INT) in distribution.sla_breach',
    `breach_severity` STRING COMMENT 'The severity classification of the breach based on business impact, used for prioritization and escalation. | Column breach_severity (STRING) in distribution.sla_breach. Valid values are `critical|high|medium|low`',
    `breach_status` STRING COMMENT 'Current state of the breach in its resolution lifecycle, tracking progress from detection through closure. | Column breach_status (STRING) in distribution.sla_breach. Valid values are `open|acknowledged|investigating|resolved|closed|disputed`',
    `breach_timestamp` TIMESTAMP COMMENT 'The exact date and time when the SLA breach was detected and recorded. This is the principal business event timestamp for the breach. | Column breach_timestamp (TIMESTAMP) in distribution.sla_breach',
    `cdn_provider` STRING COMMENT 'The CDN provider responsible for content delivery at the time of the breach, used for vendor accountability. | Column cdn_provider (STRING) in distribution.sla_breach',
    `contract_reference` STRING COMMENT 'Reference to the contract or service agreement under which the SLA commitment was made, used for dispute resolution. | Column contract_reference (STRING) in distribution.sla_breach',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.sla_breach',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this breach record was first created in the system for audit trail purposes. | Column created_timestamp (TIMESTAMP) in distribution.sla_breach',
    `detection_method` STRING COMMENT 'The method by which the SLA breach was detected, indicating whether it was proactive monitoring or reactive reporting. | Column detection_method (STRING) in distribution.sla_breach. Valid values are `automated_monitoring|customer_report|manual_audit|health_check|synthetic_test`',
    `dispute_flag` BOOLEAN COMMENT 'Indicates whether the breach determination or penalty is under dispute by the partner or service provider. | Column dispute_flag (BOOLEAN) in distribution.sla_breach',
    `dispute_reason` STRING COMMENT 'Explanation provided for disputing the breach determination, penalty calculation, or responsibility assignment. | Column dispute_reason (STRING) in distribution.sla_breach',
    `escalation_level` STRING COMMENT 'The escalation tier reached during breach resolution, indicating the organizational level involved in remediation. | Column escalation_level (STRING) in distribution.sla_breach. Valid values are `none|tier_1|tier_2|tier_3|executive`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The date and time when this breach record was last updated, tracking changes throughout the breach lifecycle. | Column last_modified_timestamp (TIMESTAMP) in distribution.sla_breach',
    `makegood_triggered_flag` BOOLEAN COMMENT 'Indicates whether a makegood (compensatory delivery or ad spot) was triggered as a result of this breach. | Column makegood_triggered_flag (BOOLEAN) in distribution.sla_breach',
    `measured_value` DECIMAL(18,2) COMMENT 'The actual measured value of the metric at the time of breach, representing the performance level that violated the SLA threshold. | Column measured_value (DECIMAL(18,6)) in distribution.sla_breach',
    `metric_name` STRING COMMENT 'The specific SLA metric that was breached, such as uptime percentage, latency, error rate, or availability. | Column metric_name (STRING) in distribution.sla_breach',
    `metric_type` STRING COMMENT 'Category of the SLA metric that was breached, classifying the nature of the performance issue. | Column metric_type (STRING) in distribution.sla_breach. Valid values are `availability|latency|throughput|error_rate|response_time|packet_loss`',
    `notes` STRING COMMENT 'Additional free-text notes or comments regarding the breach, investigation, or resolution for operational context. | Column notes (STRING) in distribution.sla_breach',
    `notification_sent_flag` BOOLEAN COMMENT 'Indicates whether breach notification was sent to affected partners, stakeholders, or customers as required by SLA terms. | Column notification_sent_flag (BOOLEAN) in distribution.sla_breach',
    `notification_timestamp` TIMESTAMP COMMENT 'The date and time when breach notification was sent to affected parties. | Column notification_timestamp (TIMESTAMP) in distribution.sla_breach',
    `partner_name` STRING COMMENT 'The name of the distribution partner or MVPD affected by the breach, relevant for partner SLA reporting. | Column partner_name (STRING) in distribution.sla_breach',
    `penalty_amount` DECIMAL(18,2) COMMENT 'The monetary penalty or service credit amount triggered by the breach, as defined in the SLA contract. | Column penalty_amount (DECIMAL(15,2)) in distribution.sla_breach',
    `penalty_applicable_flag` BOOLEAN COMMENT 'Indicates whether a contractual penalty or credit is applicable for this breach based on SLA terms. | Column penalty_applicable_flag (BOOLEAN) in distribution.sla_breach',
    `penalty_currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the penalty amount. | Column penalty_currency_code (STRING) in distribution.sla_breach. Valid values are `^[A-Z]{3}$`',
    `remediation_action` STRING COMMENT 'Description of the corrective action taken to resolve the breach and restore service to acceptable levels. | Column remediation_action (STRING) in distribution.sla_breach',
    `resolution_timestamp` TIMESTAMP COMMENT 'The date and time when the breach was resolved and service was restored to within SLA parameters. | Column resolution_timestamp (TIMESTAMP) in distribution.sla_breach',
    `root_cause_category` STRING COMMENT 'High-level categorization of the underlying cause of the SLA breach, used for trend analysis and preventive action. | Column root_cause_category (STRING) in distribution.sla_breach. Valid values are `cdn_failure|origin_failure|network_congestion|ddos_attack|configuration_error|capacity_exceeded`',
    `root_cause_description` STRING COMMENT 'Detailed narrative explanation of the root cause identified through investigation, providing context for the breach. | Column root_cause_description (STRING) in distribution.sla_breach',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.sla_breach',
    `streaming_protocol` STRING COMMENT 'The streaming protocol in use when the breach occurred, such as HLS or MPEG-DASH. | Column streaming_protocol (STRING) in distribution.sla_breach. Valid values are `HLS|MPEG-DASH|Smooth Streaming|RTMP|WebRTC`',
    `threshold_value` DECIMAL(18,2) COMMENT 'The SLA threshold value that was violated, representing the minimum acceptable performance level defined in the SLA commitment. | Column threshold_value (DECIMAL(18,6)) in distribution.sla_breach',
    `unit_of_measure` STRING COMMENT 'The unit in which the metric is measured, such as percentage, milliseconds, Mbps, or requests per second. | Column unit_of_measure (STRING) in distribution.sla_breach',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.sla_breach',
    `validated_by` STRING COMMENT 'The user or system that validated the breach measurement and determination, ensuring accuracy for reporting. | Column validated_by (STRING) in distribution.sla_breach',
    `validated_timestamp` TIMESTAMP COMMENT 'The date and time when the breach record was validated and approved for reporting or penalty processing. | Column validated_timestamp (TIMESTAMP) in distribution.sla_breach',
    `variance_percentage` DECIMAL(18,2) COMMENT 'The variance expressed as a percentage of the threshold, providing a normalized measure of breach severity. | Column variance_percentage (DECIMAL(10,4)) in distribution.sla_breach',
    `variance_value` DECIMAL(18,2) COMMENT 'The calculated difference between the measured value and the threshold value, quantifying the magnitude of the breach. | Column variance_value (DECIMAL(18,6)) in distribution.sla_breach',
    CONSTRAINT pk_sla_breach PRIMARY KEY(`sla_breach_id`)
) COMMENT 'Transactional record capturing instances where a delivery SLA commitment was violated for a distribution channel or partner. Captures breach timestamp, affected delivery channel, SLA metric breached (uptime, latency, error rate), measured value, SLA threshold, breach duration, root cause category, resolution timestamp, and whether a makegood or penalty was triggered. Supports partner SLA reporting, dispute resolution, and operational improvement tracking. | Unity Catalog table: media_broadcasting_ecm.distribution.sla_breach';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`dai_session` (
    `dai_session_id` BIGINT COMMENT 'Unique identifier for the DAI session. Primary key for the dai_session product. | Column dai_session_id (BIGINT) in distribution.dai_session',
    `ad_order_id` BIGINT COMMENT 'Foreign key linking to sales.ad_order. Business justification: DAI sessions fulfill contracted ad orders. Linking to ad_order enables order-level delivery tracking, contracted-vs-actual reconciliation, billing verification, and order fulfillment reporting. Essent | Column ad_order_id (BIGINT) in sales.dai_session',
    `sales_campaign_id` BIGINT COMMENT 'Foreign key linking to sales.campaign. Business justification: Distribution DAI sessions serve ads from specific advertising campaigns. Linking enables campaign-level delivery reporting, pacing analysis, cross-domain revenue attribution, and campaign performance  | Column campaign_id (BIGINT) in sales.dai_session',
    `channel_id` BIGINT COMMENT 'Reference to the linear or FAST channel on which the DAI session occurred. Applicable for live broadcast and FAST channel monetization. | Column channel_id (BIGINT) in scheduling.dai_session',
    `content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: Dynamic ad insertion must respect content rating for ad appropriateness (no alcohol ads in childrens programming). Real-time rating checks during ad decisioning ensure compliance. | Column content_rating_id (BIGINT) in compliance.dai_session',
    `dai_configuration_id` BIGINT COMMENT 'Foreign key linking to distribution.dai_configuration. Business justification: DAI sessions should reference the configuration used. Tracks which DAI config was applied during the session. Removes dai_provider STRING (derivable from dai_configuration). | Column dai_configuration_id (BIGINT) in distribution.dai_session',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to audience.demographic_segment. Business justification: Real-time demographic targeting drives programmatic ad decisioning, frequency capping by demo, and guaranteed audience delivery. Essential for upfront commitment fulfillment and Nielsen-rated commerci | Column demographic_segment_id (BIGINT) in audience.dai_session',
    `grant_id` BIGINT COMMENT 'Foreign key linking to rights.rights_grant. Business justification: DAI sessions insert ads into content governed by specific rights grants. Ad insertion rights, ad load limits, and ad revenue share calculations depend on the underlying rights grant. Essential for rig | Column grant_id (BIGINT) in rights.dai_session',
    `media_asset_id` BIGINT COMMENT 'Reference to the content asset (video, live stream, FAST channel) being delivered when the DAI session was executed. | Column media_asset_id (BIGINT) in mediaasset.dai_session',
    `playback_session_id` BIGINT COMMENT 'Reference to the parent streaming playback session during which this DAI session occurred. Links DAI monetization events to viewer streaming activity. | Column playback_session_id (BIGINT) in distribution.dai_session',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: DAI (dynamic ad insertion) sessions generate advertising revenue streams. Daily ad revenue reconciliation ties DAI sessions to revenue streams for accrual accounting and reconciliation with ad server  | Column revenue_stream_id (BIGINT) in finance.dai_session',
    `segment_id` BIGINT COMMENT 'Foreign key linking to audience.audience_segment. Business justification: Behavioral audience segments enable advanced programmatic targeting beyond demographics, supporting lookalike modeling, cross-platform campaign optimization, and addressable advertising in modern ad t | Column segment_id (BIGINT) in audience.dai_session',
    `streaming_endpoint_id` BIGINT COMMENT 'Reference to the streaming endpoint (CDN edge, origin server) that served the DAI-enabled stream. | Column streaming_endpoint_id (BIGINT) in distribution.dai_session',
    `subscriber_id` BIGINT COMMENT 'Unique identifier for the subscriber or viewer associated with this DAI session. Enables personalized ad targeting and frequency capping. | Column subscriber_id (BIGINT) in subscriber.dai_session',
    `talent_profile_id` BIGINT COMMENT 'Foreign key linking to talent.talent_profile. Business justification: Backend gross participation clauses in talent contracts require tracking ad revenue generated during content delivery featuring specific talent. Broadcasters must link dynamic ad insertion sessions to | Column talent_profile_id (BIGINT) in talent.dai_session',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in distribution.dai_session',
    `_source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in distribution.dai_session',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in distribution.dai_session',
    `ad_decision_server_response_time_ms` STRING COMMENT 'Time in milliseconds taken by the ad decision server to respond with ad selection. Critical for measuring DAI latency and QoS. | Column ad_decision_server_response_time_ms (INT) in distribution.dai_session',
    `ad_decision_server_url` STRING COMMENT 'URL of the ad decision server (ADS) that was queried to determine which ads to insert. Typically a VAST or VMAP endpoint. | Column ad_decision_server_url (STRING) in distribution.dai_session',
    `ad_pod_duration_seconds` DECIMAL(18,2) COMMENT 'Total duration of the ad pod in seconds. Represents the available inventory window for ad insertion. | Column ad_pod_duration_seconds (DECIMAL(10,3)) in distribution.dai_session',
    `ad_pod_position` STRING COMMENT 'Position of the ad pod within the content stream. Indicates whether ads were served before content (pre-roll), during content (mid-roll), or after content (post-roll). | Column ad_pod_position (STRING) in distribution.dai_session. Valid values are `pre_roll|mid_roll|post_roll|overlay|pause_ad|companion`',
    `ad_pod_sequence_number` STRING COMMENT 'Sequential number of this ad pod within the content playback session. Enables tracking of multiple ad breaks within a single viewing session. | Column ad_pod_sequence_number (INT) in distribution.dai_session',
    `ad_targeting_segment_ids` STRING COMMENT 'Comma-separated list of audience segment IDs applied for ad targeting during this DAI session. Links to audience segmentation and personalization strategies. | Column ad_targeting_segment_ids (STRING) in distribution.dai_session',
    `ads_fallback_count` STRING COMMENT 'Number of fallback or house ads served when primary ad inventory was unavailable. Indicates unfilled demand. | Column ads_fallback_count (INT) in distribution.dai_session',
    `ads_inserted_count` STRING COMMENT 'Number of ads successfully inserted and delivered during this DAI session. Used to calculate fill rate and monetization efficiency. | Column ads_inserted_count (INT) in distribution.dai_session',
    `ads_requested_count` STRING COMMENT 'Number of ad slots requested from the ad decision server for this DAI session. Represents the maximum fill capacity of the ad pod. | Column ads_requested_count (INT) in distribution.dai_session',
    `app_version` STRING COMMENT 'Version of the streaming application or player that executed the DAI session. Used for troubleshooting and feature compatibility analysis. | Column app_version (STRING) in distribution.dai_session',
    `blackout_override_flag` BOOLEAN COMMENT 'Indicates whether geographic blackout restrictions were overridden for this DAI session. True if blackout rules were bypassed (e.g., for authenticated subscribers). | Column blackout_override_flag (BOOLEAN) in distribution.dai_session',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.dai_session',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this DAI session record was first created in the system. Used for data lineage and audit trail. | Column created_timestamp (TIMESTAMP) in distribution.dai_session',
    `device_type` STRING COMMENT 'Type of device on which the DAI session was delivered. Influences ad format compatibility and targeting strategies. [ENUM-REF-CANDIDATE: smart_tv|mobile|tablet|desktop|set_top_box|gaming_console|streaming_stick|other — 8 candidates stripped; promote to reference product] | Column device_type (STRING) in distribution.dai_session',
    `drm_enforcement_flag` BOOLEAN COMMENT 'Indicates whether DRM protection was enforced on the ad-stitched stream. True if ads were delivered with DRM encryption. | Column drm_enforcement_flag (BOOLEAN) in distribution.dai_session',
    `error_code` STRING COMMENT 'Error code returned if the DAI session encountered a failure. Used for troubleshooting ad delivery issues and optimizing fill rates. | Column error_code (STRING) in distribution.dai_session',
    `error_message` STRING COMMENT 'Human-readable error message describing the failure reason if the DAI session did not complete successfully. | Column error_message (STRING) in distribution.dai_session',
    `fill_rate_percentage` DECIMAL(18,2) COMMENT 'Percentage of requested ad slots that were successfully filled with paid ads. Calculated as (ads_inserted_count / ads_requested_count) * 100. Key monetization metric. | Column fill_rate_percentage (DECIMAL(5,2)) in distribution.dai_session',
    `frequency_cap_applied_flag` BOOLEAN COMMENT 'Indicates whether frequency capping rules were applied to limit ad repetition for this viewer. True if frequency cap was enforced. | Column frequency_cap_applied_flag (BOOLEAN) in distribution.dai_session',
    `geographic_country_code` STRING COMMENT 'Three-letter ISO country code representing the viewers geographic location. Derived from IP address or device GPS. Used for geo-targeted ad campaigns. | Column geographic_country_code (STRING) in distribution.dai_session. Valid values are `^[A-Z]{3}$`',
    `geographic_dma_code` STRING COMMENT 'Nielsen Designated Market Area code representing the viewers media market. Critical for local advertising sales and audience measurement alignment. | Column geographic_dma_code (STRING) in distribution.dai_session',
    `geographic_region` STRING COMMENT 'State, province, or region where the viewer was located during the DAI session. Enables regional ad targeting and compliance with local advertising regulations. | Column geographic_region (STRING) in distribution.dai_session',
    `platform_type` STRING COMMENT 'Operating system or platform on which the DAI-enabled player was running. Critical for device-specific ad targeting and compatibility. [ENUM-REF-CANDIDATE: web|ios|android|roku|fire_tv|apple_tv|samsung_tizen|lg_webos|xbox|playstation|other — 11 candidates stripped; promote to reference product] | Column platform_type (STRING) in distribution.dai_session',
    `scte35_cue_type` STRING COMMENT 'Type of SCTE-35 cue message that triggered the DAI session. Indicates the nature of the ad opportunity (splice insert, time signal, segmentation descriptor). [ENUM-REF-CANDIDATE: splice_insert|time_signal|segmentation_descriptor|provider_advertisement|distributor_advertisement|program_start|program_end|chapter_start|break_start|break_end — 10 candidates stripped; promote to reference product] | Column scte35_cue_type (STRING) in distribution.dai_session',
    `scte35_signal_timestamp` TIMESTAMP COMMENT 'Timestamp of the SCTE-35 cue message that triggered the DAI opportunity. Critical for synchronizing ad insertion with content breaks. | Column scte35_signal_timestamp (TIMESTAMP) in distribution.dai_session',
    `session_end_timestamp` TIMESTAMP COMMENT 'Timestamp when the DAI session completed. Marks the end of ad pod delivery and return to content. | Column session_end_timestamp (TIMESTAMP) in distribution.dai_session',
    `session_start_timestamp` TIMESTAMP COMMENT 'Timestamp when the DAI session was initiated. Represents the moment the ad decision server was queried for this ad opportunity. | Column session_start_timestamp (TIMESTAMP) in distribution.dai_session',
    `session_status` STRING COMMENT 'Final status of the DAI session. Indicates whether the session completed successfully, partially filled, failed, timed out, or was abandoned by the viewer. | Column session_status (STRING) in distribution.dai_session. Valid values are `completed|partial|failed|timeout|abandoned`',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.dai_session',
    `stitching_mode` STRING COMMENT 'Method used to insert ads into the stream. Server-side stitching (SSAI) integrates ads at the CDN level; client-side stitching occurs in the player. | Column stitching_mode (STRING) in distribution.dai_session. Valid values are `server_side|client_side|hybrid`',
    `streaming_protocol` STRING COMMENT 'Adaptive bitrate streaming protocol used for DAI delivery (HLS, MPEG-DASH, Smooth Streaming). Affects manifest manipulation and ad stitching approach. | Column streaming_protocol (STRING) in distribution.dai_session. Valid values are `hls|dash|smooth_streaming|hds`',
    `total_ad_duration_seconds` DECIMAL(18,2) COMMENT 'Total duration of all ads actually delivered during this DAI session. May differ from ad_pod_duration_seconds if pod was not fully filled. | Column total_ad_duration_seconds (DECIMAL(10,3)) in distribution.dai_session',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.dai_session',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this DAI session record was last modified. Tracks changes to session status or post-session reconciliation updates. | Column updated_timestamp (TIMESTAMP) in distribution.dai_session',
    `viewer_ip_address` STRING COMMENT 'IP address of the viewer device at the time of the DAI session. Used for geo-targeting and fraud detection. May be considered PII under GDPR. | Column viewer_ip_address (STRING) in distribution.dai_session',
    CONSTRAINT pk_dai_session PRIMARY KEY(`dai_session_id`)
) COMMENT 'Transactional record capturing Dynamic Ad Insertion (DAI) sessions executed during streaming delivery. Captures session identifier, delivery channel or stream, viewer session reference, ad pod position (pre-roll, mid-roll, post-roll), SCTE-35 signal timestamp, ad decision server response, number of ads inserted, fill rate, fallback ad flag, and DAI provider (e.g., Google DAI, Yospace). Supports AVOD and FAST channel monetization reconciliation and ad fill rate optimization. | Unity Catalog table: media_broadcasting_ecm.distribution.dai_session';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`retransmission_consent` (
    `retransmission_consent_id` BIGINT COMMENT 'Primary key for retransmission_consent | Column retransmission_consent_id (BIGINT) in distribution.retransmission_consent',
    `broadcast_license_id` BIGINT COMMENT 'Foreign key linking to compliance.broadcast_license. Business justification: Retransmission consent records must directly reference broadcast license for FCC filing, public inspection file inclusion, and must-carry election tracking. License is the regulatory anchor for consen | Column broadcast_license_id (BIGINT) in compliance.retransmission_consent',
    `carriage_agreement_id` BIGINT COMMENT 'Foreign key linking to distribution.carriage_agreement. Business justification: Retransmission consent is often tied to carriage agreements. Consent enables carriage under specific agreement terms. Essential for legal compliance tracking. | Column carriage_agreement_id (BIGINT) in distribution.retransmission_consent',
    `distribution_partner_id` BIGINT COMMENT 'Foreign key linking to distribution.distribution_partner. Business justification: Retransmission consent is granted to specific MVPD partners (MVPDs are distribution partners). retransmission_consent.mvpd_id should FK to distribution_partner. Removes mvpd_id BIGINT and mvpd_name ST | Column distribution_partner_id (BIGINT) in distribution.retransmission_consent',
    `license_agreement_id` BIGINT COMMENT 'Foreign key linking to rights.license_agreement. Business justification: Retransmission consent agreements are specialized broadcast rights licenses. Linking enables rights chain validation, ensures MVPDs have proper authorization, and supports fee reconciliation between r | Column license_agreement_id (BIGINT) in rights.retransmission_consent',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Retransmission consent agreements are regulatory/legal contracts requiring negotiator ownership for FCC compliance, blackout coordination, must-carry elections, and good-faith negotiation requirements | Column negotiator_employee_id (BIGINT) in workforce.retransmission_consent',
    `partner_id` BIGINT COMMENT 'Identifier of the broadcast station granting retransmission consent authorization. | Column partner_id (BIGINT) in partner.retransmission_consent',
    `opportunity_id` BIGINT COMMENT 'Foreign key linking to sales.opportunity. Business justification: Retransmission consent agreements originate from sales opportunities during broadcaster-MVPD negotiations. Tracks negotiation lifecycle from opportunity through executed consent agreement. Critical fo | Column source_opportunity_id (BIGINT) in sales.retransmission_consent',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in distribution.retransmission_consent',
    `_source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in distribution.retransmission_consent',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in distribution.retransmission_consent',
    `approval_date` DATE COMMENT 'Date when the retransmission consent agreement received final internal approval and authorization for execution. | Column approval_date (DATE) in distribution.retransmission_consent',
    `approved_by` STRING COMMENT 'Name or identifier of the executive or legal authority who approved the retransmission consent agreement on behalf of the broadcaster. | Column approved_by (STRING) in distribution.retransmission_consent',
    `authorized_dma_list` STRING COMMENT 'Comma-separated list of Nielsen DMA codes where the MVPD is authorized to retransmit the broadcast signal (e.g., 501,602,803). | Column authorized_dma_list (STRING) in distribution.retransmission_consent',
    `blackout_provision_flag` BOOLEAN COMMENT 'Indicates whether the agreement includes geographic blackout provisions restricting retransmission in certain markets or during specific events. | Column blackout_provision_flag (BOOLEAN) in distribution.retransmission_consent',
    `blackout_terms` STRING COMMENT 'Detailed description of blackout restrictions, including affected content types, geographic areas, and triggering conditions. | Column blackout_terms (STRING) in distribution.retransmission_consent',
    `cash_compensation_amount` DECIMAL(18,2) COMMENT 'Monetary compensation amount paid by the MVPD to the broadcaster per billing period. Null if compensation is non-cash. | Column cash_compensation_amount (DECIMAL(15,2)) in distribution.retransmission_consent',
    `channel_carriage_commitment` STRING COMMENT 'Description of channel carriage commitments provided by the MVPD as part of the retransmission consent agreement (e.g., carriage of affiliated digital subchannels). | Column channel_carriage_commitment (STRING) in distribution.retransmission_consent',
    `compensation_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for cash compensation (e.g., USD, CAD, GBP). | Column compensation_currency_code (STRING) in distribution.retransmission_consent. Valid values are `^[A-Z]{3}$`',
    `compensation_frequency` STRING COMMENT 'Billing frequency for cash compensation payments from MVPD to broadcaster. | Column compensation_frequency (STRING) in distribution.retransmission_consent. Valid values are `monthly|quarterly|annually|one_time`',
    `compensation_type` STRING COMMENT 'Primary form of compensation provided by the MVPD to the broadcaster in exchange for retransmission consent. | Column compensation_type (STRING) in distribution.retransmission_consent. Valid values are `cash|reverse_compensation|channel_carriage|promotional|hybrid|none`',
    `consent_agreement_number` STRING COMMENT 'Externally-known unique business identifier for the retransmission consent agreement, typically formatted as RTC-YYYYNNNN. | Column consent_agreement_number (STRING) in distribution.retransmission_consent. Valid values are `^RTC-[0-9]{8}$`',
    `consent_status` STRING COMMENT 'Current lifecycle status of the retransmission consent agreement. [ENUM-REF-CANDIDATE: draft|negotiation|active|expired|terminated|suspended|disputed — 7 candidates stripped; promote to reference product] | Column consent_status (STRING) in distribution.retransmission_consent',
    `consent_type` STRING COMMENT 'Type of carriage authorization: retransmission consent (negotiated) or must-carry (mandatory under FCC rules). | Column consent_type (STRING) in distribution.retransmission_consent. Valid values are `retransmission_consent|must_carry`',
    `contract_document_reference` STRING COMMENT 'Reference identifier or file path to the executed retransmission consent contract document in the document management system. | Column contract_document_reference (STRING) in distribution.retransmission_consent',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.retransmission_consent',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this retransmission consent record was first created in the system. | Column created_timestamp (TIMESTAMP) in distribution.retransmission_consent',
    `dispute_resolution_method` STRING COMMENT 'Agreed-upon method for resolving disputes arising from the retransmission consent agreement. | Column dispute_resolution_method (STRING) in distribution.retransmission_consent. Valid values are `arbitration|mediation|litigation|FCC_complaint`',
    `effective_date` DATE COMMENT 'Date when the retransmission consent agreement becomes legally binding and carriage authorization begins. | Column effective_date (DATE) in distribution.retransmission_consent',
    `expiry_date` DATE COMMENT 'Date when the retransmission consent agreement terminates and carriage authorization ends. Nullable for indefinite agreements. | Column expiry_date (DATE) in distribution.retransmission_consent',
    `fcc_filing_reference` STRING COMMENT 'Reference number or identifier for any FCC filings, notifications, or complaints associated with this retransmission consent agreement. | Column fcc_filing_reference (STRING) in distribution.retransmission_consent',
    `geographic_scope` STRING COMMENT 'Geographic coverage scope of the retransmission consent agreement. | Column geographic_scope (STRING) in distribution.retransmission_consent. Valid values are `local|regional|national`',
    `good_faith_negotiation_flag` BOOLEAN COMMENT 'Indicates whether both parties certified compliance with FCC good faith negotiation requirements during retransmission consent discussions. | Column good_faith_negotiation_flag (BOOLEAN) in distribution.retransmission_consent',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this retransmission consent record was last updated or modified. | Column last_modified_timestamp (TIMESTAMP) in distribution.retransmission_consent',
    `modified_by_user` STRING COMMENT 'Username or identifier of the user who last modified this retransmission consent record. | Column modified_by_user (STRING) in distribution.retransmission_consent',
    `must_carry_election_date` DATE COMMENT 'Date when the broadcaster formally elected must-carry status with the MVPD. Null if retransmission consent was negotiated. | Column must_carry_election_date (DATE) in distribution.retransmission_consent',
    `must_carry_election_flag` BOOLEAN COMMENT 'Indicates whether the broadcaster elected must-carry status instead of negotiating retransmission consent. True if must-carry was elected. | Column must_carry_election_flag (BOOLEAN) in distribution.retransmission_consent',
    `mvpd_type` STRING COMMENT 'Classification of the MVPD platform type receiving retransmission consent. | Column mvpd_type (STRING) in distribution.retransmission_consent. Valid values are `cable|satellite|telco|vMVPD|IPTV`',
    `negotiation_completion_date` DATE COMMENT 'Date when retransmission consent negotiations were successfully concluded and agreement was reached. | Column negotiation_completion_date (DATE) in distribution.retransmission_consent',
    `negotiation_start_date` DATE COMMENT 'Date when retransmission consent negotiations formally commenced between broadcaster and MVPD. | Column negotiation_start_date (DATE) in distribution.retransmission_consent',
    `notes` STRING COMMENT 'Free-text field for additional notes, special conditions, or contextual information regarding the retransmission consent agreement. | Column notes (STRING) in distribution.retransmission_consent',
    `promotional_commitment` STRING COMMENT 'Description of promotional support commitments provided by the MVPD (e.g., on-air promotion, co-marketing campaigns). | Column promotional_commitment (STRING) in distribution.retransmission_consent',
    `renewal_notice_days` STRING COMMENT 'Number of days advance notice required before expiry date to trigger renewal or renegotiation process. | Column renewal_notice_days (INT) in distribution.retransmission_consent',
    `renewal_option_flag` BOOLEAN COMMENT 'Indicates whether the agreement includes an automatic renewal option or requires renegotiation at expiry. | Column renewal_option_flag (BOOLEAN) in distribution.retransmission_consent',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.retransmission_consent',
    `termination_clause` STRING COMMENT 'Description of conditions under which either party may terminate the retransmission consent agreement prior to expiry date. | Column termination_clause (STRING) in distribution.retransmission_consent',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.retransmission_consent',
    CONSTRAINT pk_retransmission_consent PRIMARY KEY(`retransmission_consent_id`)
) COMMENT 'Master record documenting retransmission consent authorizations granted to MVPDs and vMVPDs to rebroadcast over-the-air broadcast signals. Captures grantor broadcaster, grantee MVPD/vMVPD, authorized markets (DMAs), consent effective date, consent expiry date, compensation terms (cash, channel carriage, promotional commitments), must-carry election status, and negotiation history flags. Governed by FCC retransmission consent regulations. | Unity Catalog table: media_broadcasting_ecm.distribution.retransmission_consent Akamai CDN integration supported.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`subscriber_count_report` (
    `subscriber_count_report_id` BIGINT COMMENT 'Unique identifier for the subscriber count report record. Primary key. | Column subscriber_count_report_id (BIGINT) in distribution.subscriber_count_report',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Subscriber count reports drive carriage fee invoicing and require auditor ownership for variance investigation, dispute resolution, audit rights exercise, and third-party auditor coordination. Essenti | Column auditor_employee_id (BIGINT) in workforce.subscriber_count_report',
    `carriage_agreement_id` BIGINT COMMENT 'Foreign key linking to distribution.carriage_agreement. Business justification: Subscriber count reports validate carriage agreement terms. Reports are submitted per agreement for billing purposes. Removes contract_reference STRING (derivable from carriage_agreement.agreement_num | Column carriage_agreement_id (BIGINT) in distribution.subscriber_count_report',
    `channel_id` BIGINT COMMENT 'Reference to the specific channel or channel tier for which subscriber counts are being reported. | Column channel_id (BIGINT) in scheduling.subscriber_count_report',
    `distribution_partner_id` BIGINT COMMENT 'Reference to the MVPD (Multichannel Video Programming Distributor) or vMVPD (Virtual Multichannel Video Programming Distributor) partner submitting the subscriber count report. | Column distribution_partner_id (BIGINT) in distribution.subscriber_count_report',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Subscriber counts are reported by DMA for carriage fee calculation, retransmission consent compliance, and Nielsen universe estimation. Market-level reporting is mandated in distribution partner contr | Column market_coverage_id (BIGINT) in audience.subscriber_count_report',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in distribution.subscriber_count_report',
    `_source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in distribution.subscriber_count_report',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in distribution.subscriber_count_report',
    `approval_date` DATE COMMENT 'Date on which the subscriber count report was formally approved for use in carriage fee invoice generation. | Column approval_date (DATE) in distribution.subscriber_count_report',
    `approval_status` STRING COMMENT 'Current approval status of the subscriber count report in the verification and reconciliation workflow. | Column approval_status (STRING) in distribution.subscriber_count_report. Valid values are `pending|approved|rejected|disputed|under_review|conditionally_approved`',
    `approved_by` STRING COMMENT 'Name or identifier of the internal user or role who approved the subscriber count report for carriage fee calculation. | Column approved_by (STRING) in distribution.subscriber_count_report',
    `audit_report_reference` STRING COMMENT 'Reference identifier to the formal audit report document associated with this subscriber count verification, if a third-party audit was conducted. | Column audit_report_reference (STRING) in distribution.subscriber_count_report',
    `audit_rights_exercised` BOOLEAN COMMENT 'Indicator of whether contractual audit rights were formally exercised for this reporting period, triggering enhanced verification procedures. | Column audit_rights_exercised (BOOLEAN) in distribution.subscriber_count_report',
    `auditor_notes` STRING COMMENT 'Internal notes and observations recorded by the auditor or verification team during the subscriber count review process. | Column auditor_notes (STRING) in distribution.subscriber_count_report',
    `carriage_fee_per_subscriber` DECIMAL(18,2) COMMENT 'Contractual per-subscriber carriage fee rate applicable to this reporting period, used to calculate total carriage fee invoice amount. | Column carriage_fee_per_subscriber (DECIMAL(10,4)) in distribution.subscriber_count_report',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.subscriber_count_report',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this subscriber count report record was first created in the system. | Column created_timestamp (TIMESTAMP) in distribution.subscriber_count_report',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the carriage fee amount (e.g., USD, EUR, GBP). | Column currency_code (STRING) in distribution.subscriber_count_report. Valid values are `^[A-Z]{3}$`',
    `dispute_flag` BOOLEAN COMMENT 'Indicator of whether the distribution partner has formally disputed the verified subscriber count or variance findings. | Column dispute_flag (BOOLEAN) in distribution.subscriber_count_report',
    `dispute_reason` STRING COMMENT 'Explanation provided by the distribution partner for disputing the verified subscriber count or audit findings. | Column dispute_reason (STRING) in distribution.subscriber_count_report',
    `dispute_resolution_status` STRING COMMENT 'Current status of any dispute resolution process related to this subscriber count report. | Column dispute_resolution_status (STRING) in distribution.subscriber_count_report. Valid values are `open|in_negotiation|resolved|escalated|arbitration`',
    `invoice_generated_flag` BOOLEAN COMMENT 'Indicator of whether a carriage fee invoice has been generated based on this subscriber count report. | Column invoice_generated_flag (BOOLEAN) in distribution.subscriber_count_report',
    `invoice_reference` STRING COMMENT 'Reference identifier to the carriage fee invoice generated from this subscriber count report. | Column invoice_reference (STRING) in distribution.subscriber_count_report',
    `modified_timestamp` TIMESTAMP COMMENT 'Date and time when this subscriber count report record was last modified or updated. | Column modified_timestamp (TIMESTAMP) in distribution.subscriber_count_report',
    `notes` STRING COMMENT 'General notes and comments related to this subscriber count report, capturing additional context or special circumstances. | Column notes (STRING) in distribution.subscriber_count_report',
    `report_number` STRING COMMENT 'Externally-known unique identifier for this subscriber count report, used for contractual reference and audit tracking. | Column report_number (STRING) in distribution.subscriber_count_report. Valid values are `^[A-Z0-9]{3,20}$`',
    `report_status` STRING COMMENT 'Current lifecycle status of the subscriber count report in the end-to-end reporting and reconciliation process. | Column report_status (STRING) in distribution.subscriber_count_report. Valid values are `draft|submitted|under_verification|verified|invoiced|archived`',
    `reported_subscriber_count` BIGINT COMMENT 'Total number of subscribers reported by the distribution partner for the specified channel and period, as submitted by the MVPD or vMVPD. | Column reported_subscriber_count (BIGINT) in distribution.subscriber_count_report',
    `reporting_period_end_date` DATE COMMENT 'Last day of the period covered by this subscriber count report. | Column reporting_period_end_date (DATE) in distribution.subscriber_count_report',
    `reporting_period_start_date` DATE COMMENT 'First day of the period covered by this subscriber count report. | Column reporting_period_start_date (DATE) in distribution.subscriber_count_report',
    `reporting_period_type` STRING COMMENT 'Frequency of the subscriber count reporting period as defined in the carriage agreement (monthly, quarterly, annual, or custom). | Column reporting_period_type (STRING) in distribution.subscriber_count_report. Valid values are `monthly|quarterly|annual|custom`',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.subscriber_count_report',
    `submission_date` DATE COMMENT 'Date on which the distribution partner submitted the subscriber count report to the broadcaster. | Column submission_date (DATE) in distribution.subscriber_count_report',
    `submission_timestamp` TIMESTAMP COMMENT 'Precise date and time when the subscriber count report was received by the broadcasters system. | Column submission_timestamp (TIMESTAMP) in distribution.subscriber_count_report',
    `third_party_auditor` STRING COMMENT 'Name of the external audit firm or third-party verification service engaged to validate subscriber counts, if applicable. | Column third_party_auditor (STRING) in distribution.subscriber_count_report',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.subscriber_count_report',
    `variance_count` BIGINT COMMENT 'Numerical difference between reported subscriber count and verified subscriber count (verified minus reported). | Column variance_count (BIGINT) in distribution.subscriber_count_report',
    `variance_explanation` STRING COMMENT 'Detailed explanation provided by the distribution partner or internal audit team describing the reason for any variance between reported and verified counts. | Column variance_explanation (STRING) in distribution.subscriber_count_report',
    `variance_flag` BOOLEAN COMMENT 'Indicator of whether a material variance exists between reported and verified subscriber counts, triggering additional review or dispute resolution. | Column variance_flag (BOOLEAN) in distribution.subscriber_count_report',
    `variance_percentage` DECIMAL(18,2) COMMENT 'Percentage variance between reported and verified subscriber counts, calculated as (variance_count / reported_subscriber_count) * 100. | Column variance_percentage (DECIMAL(5,2)) in distribution.subscriber_count_report',
    `verification_date` DATE COMMENT 'Date on which the internal verification and audit process was completed for this subscriber count report. | Column verification_date (DATE) in distribution.subscriber_count_report',
    `verification_method` STRING COMMENT 'Method used to verify the reported subscriber count (automated system check, manual review, third-party audit, statistical sampling, or full audit). | Column verification_method (STRING) in distribution.subscriber_count_report. Valid values are `automated|manual|third_party_audit|sampling|full_audit`',
    `verified_subscriber_count` BIGINT COMMENT 'Subscriber count after internal verification and audit processes, used as the basis for carriage fee calculation. | Column verified_subscriber_count (BIGINT) in distribution.subscriber_count_report',
    CONSTRAINT pk_subscriber_count_report PRIMARY KEY(`subscriber_count_report_id`)
) COMMENT 'Transactional record capturing periodic subscriber count certifications submitted by MVPD and vMVPD partners, used as the basis for per-subscriber carriage fee calculation. Captures reporting period (monthly/quarterly), distribution partner, channel or channel tier, reported subscriber count, verified subscriber count, variance flag, variance explanation, submission date, verification date, approval status, and auditor notes. Feeds carriage_fee_invoice generation and revenue assurance reconciliation. Subject to contractual audit rights. Distinct from subscriber master data owned by the subscriber domain. | Unity Catalog table: media_broadcasting_ecm.distribution.subscriber_count_report';

