    `_source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in distribution.channel_lineup',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in distribution.channel_lineup',
    `audio_description_available` BOOLEAN COMMENT 'Indicates whether audio description (descriptive video service) is available for visually impaired subscribers. | Column audio_description_available (BOOLEAN) in distribution.channel_lineup',
    `blackout_region_codes` STRING COMMENT 'Comma-separated list of geographic region codes where blackout restrictions apply for this channel (e.g., DMA codes, postal codes, state codes). | Column blackout_region_codes (STRING) in distribution.channel_lineup',
    `blackout_rules_applicable` BOOLEAN COMMENT 'Indicates whether geographic broadcast restriction (blackout) rules apply to this channel within the lineup. | Column blackout_rules_applicable (BOOLEAN) in distribution.channel_lineup',
    `carriage_fee_currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the carriage fee (e.g., USD, EUR, GBP). | Column carriage_fee_currency_code (STRING) in distribution.channel_lineup. Valid values are `^[A-Z]{3}$`',
    `carriage_fee_per_subscriber` DECIMAL(18,2) COMMENT 'Monthly fee paid by the MVPD/vMVPD to the content provider per subscriber who has access to this channel within the lineup. Used for carriage fee calculation and revenue assurance. | Column carriage_fee_per_subscriber (DECIMAL(12,4)) in distribution.channel_lineup',
    `carriage_type` STRING COMMENT 'Legal basis for the channels inclusion in the lineup: must-carry (mandatory FCC requirement), retransmission consent (negotiated rebroadcast authorization), or negotiated carriage agreement. | Column carriage_type (STRING) in distribution.channel_lineup. Valid values are `must_carry|retransmission_consent|negotiated`',
    `channel_display_name` STRING COMMENT 'The branded name of the channel as displayed to subscribers in the EPG (Electronic Program Guide) for this specific lineup. | Column channel_display_name (STRING) in distribution.channel_lineup',
    `channel_position_number` STRING COMMENT 'Logical channel number or position assigned to the channel within this lineup (e.g., channel 101, channel 502). Used for Electronic Program Guide (EPG) display and subscriber navigation. | Column channel_position_number (INT) in distribution.channel_lineup',
    `closed_caption_required` BOOLEAN COMMENT 'Indicates whether closed captioning is mandated for this channel per FCC accessibility requirements. | Column closed_caption_required (BOOLEAN) in distribution.channel_lineup',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.channel_lineup',
