CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`playout_feed` (
    `playout_feed_id` BIGINT COMMENT 'Unique identifier for the playout feed. Primary key for the playout feed entity representing a discrete output stream from the playout automation system. | Column playout_feed_id (BIGINT) in distribution.playout_feed',
    `abr_profile_id` BIGINT COMMENT 'Foreign key linking to distribution.abr_profile. Business justification: Playout feeds use ABR profiles for encoding. Each feed has a specific ABR profile for multi-bitrate delivery. Essential for encoding configuration. | Column abr_profile_id (BIGINT) in distribution.playout_feed',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: Playout feeds originate from facilities housing playout automation. Required for playout system maintenance scheduling and facility failover coordination. | Column broadcast_facility_id (BIGINT) in technology.playout_feed',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel associated with this playout feed. Links the feed to its delivery channel configuration. | Column channel_id (BIGINT) in scheduling.playout_feed',
    `drm_policy_id` BIGINT COMMENT 'Foreign key linking to distribution.drm_policy. Business justification: Playout feeds enforce DRM policies. Each feed has DRM requirements for content protection. Removes encryption_enabled BOOLEAN and encryption_method STRING (derivable from drm_policy). | Column drm_policy_id (BIGINT) in distribution.playout_feed',
    `encoder_config_id` BIGINT COMMENT 'Foreign key linking to technology.encoder_config. Business justification: Playout feeds are encoded by encoder configurations. Required for playout signal chain tracking and encoder assignment management. | Column encoder_config_id (BIGINT) in technology.playout_feed',
    `failover_feed_id` BIGINT COMMENT 'Reference to the backup playout feed that will take over in case of failure of this primary feed, enabling high availability and business continuity. | Column failover_feed_id (BIGINT) in distribution.playout_feed',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Playout feeds are broadcast operations infrastructure requiring engineering ownership for failover testing, graphics overlay management, SCTE-35 configuration, and automation system integration. Essen | Column playout_engineer_employee_id (BIGINT) in workforce.playout_feed',
    `signal_route_id` BIGINT COMMENT 'Foreign key linking to distribution.signal_route. Business justification: Playout feeds are routed via signal routes. Each feed uses a signal route for distribution. Essential for feed routing and failover management. | Column signal_route_id (BIGINT) in distribution.playout_feed',
    `streaming_endpoint_id` BIGINT COMMENT 'Foreign key linking to distribution.streaming_endpoint. Business justification: Playout feeds output to streaming endpoints. Each feed targets a specific endpoint for distribution. Removes output_destination_url STRING (derivable from streaming_endpoint.endpoint_url). | Column streaming_endpoint_id (BIGINT) in distribution.playout_feed',
    `transmission_equipment_id` BIGINT COMMENT 'Foreign key linking to technology.transmission_equipment. Business justification: Playout feeds are generated by specific transmission equipment. Required for equipment lifecycle management and redundancy planning. | Column transmission_equipment_id (BIGINT) in technology.playout_feed',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in distribution.playout_feed',
    `_source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in distribution.playout_feed',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in distribution.playout_feed',
    `activated_timestamp` TIMESTAMP COMMENT 'Timestamp when the playout feed was activated and began operational broadcasting, marking the start of live service. | Column activated_timestamp (TIMESTAMP) in distribution.playout_feed',
    `aspect_ratio` STRING COMMENT 'Video aspect ratio for the playout feed output: 4:3 for standard definition, 16:9 for widescreen HD/UHD, or 21:9 for ultra-widescreen cinema formats. | Column aspect_ratio (NUMERIC) in distribution.playout_feed',
    `audio_bitrate_kbps` STRING COMMENT 'Target audio bitrate in kilobits per second (kbps) for the playout feed audio output, determining audio quality and bandwidth consumption. | Column audio_bitrate_kbps (INT) in distribution.playout_feed',
    `audio_channel_config` STRING COMMENT 'Audio channel layout configuration for the playout feed: mono, stereo, 5.1 surround, 7.1 surround, or Dolby Atmos immersive audio. | Column audio_channel_config (STRING) in distribution.playout_feed. Valid values are `mono|stereo|5.1|7.1|Dolby Atmos`',
    `audio_codec` STRING COMMENT 'Audio compression codec used for encoding the playout feed audio: Advanced Audio Coding (AAC), Dolby Digital (AC-3), Dolby Digital Plus (E-AC-3), MPEG-1 Layer II, or Opus. | Column audio_codec (STRING) in distribution.playout_feed. Valid values are `AAC|AC-3|E-AC-3|MPEG-1 Layer II|Opus`',
    `automation_mode` STRING COMMENT 'Level of automation for playout operations: fully automated with no operator intervention, semi-automated requiring operator approval for certain events, or manual requiring operator control for all playout actions. | Column automation_mode (STRING) in distribution.playout_feed. Valid values are `fully_automated|semi_automated|manual`',
    `branding_profile` STRING COMMENT 'Name or identifier of the branding profile applied to this playout feed, controlling channel logos, watermarks, and visual identity elements. | Column branding_profile (STRING) in distribution.playout_feed',
    `closed_caption_enabled` BOOLEAN COMMENT 'Indicates whether closed captioning (CEA-608, CEA-708) is enabled and embedded in the playout feed output for accessibility compliance. | Column closed_caption_enabled (BOOLEAN) in distribution.playout_feed',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.playout_feed',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the playout feed record was first created in the system, capturing the initial data entry event for audit and tracking purposes. | Column created_timestamp (TIMESTAMP) in distribution.playout_feed',
    `deactivated_timestamp` TIMESTAMP COMMENT 'Timestamp when the playout feed was deactivated and ceased broadcasting operations, marking the end of service or transition to offline status. | Column deactivated_timestamp (TIMESTAMP) in distribution.playout_feed',
    `failover_trigger_mode` STRING COMMENT 'Method by which failover to the backup feed is initiated: automatic based on health monitoring, manual operator intervention, or scheduled for planned maintenance. | Column failover_trigger_mode (STRING) in distribution.playout_feed. Valid values are `automatic|manual|scheduled`',
    `feed_code` STRING COMMENT 'Unique business identifier code for the playout feed used in scheduling systems, traffic systems, and operational workflows. | Column feed_code (STRING) in distribution.playout_feed',
    `feed_name` STRING COMMENT 'Human-readable name of the playout feed used for identification and operational reference within the playout automation system. | Column feed_name (STRING) in distribution.playout_feed',
    `feed_type` STRING COMMENT 'Classification of the playout feed indicating its operational role: primary broadcast feed, backup feed for failover, redundant feed for high availability, test feed for validation, or preview feed for quality control. | Column feed_type (STRING) in distribution.playout_feed. Valid values are `primary|backup|redundant|test|preview`',
    `frame_rate` DECIMAL(18,2) COMMENT 'Video frame rate in frames per second (fps) for the playout feed output, following broadcast standards for different regions and formats. | Column frame_rate (DECIMAL(18,2)) in distribution.playout_feed',
    `graphics_overlay_enabled` BOOLEAN COMMENT 'Indicates whether real-time graphics overlay (bugs, tickers, lower thirds, branding elements) is enabled for this playout feed. | Column graphics_overlay_enabled (BOOLEAN) in distribution.playout_feed',
    `graphics_template_code` STRING COMMENT 'Reference to the graphics template configuration used for branding, bugs, and overlay elements on this playout feed. | Column graphics_template_code (STRING) in distribution.playout_feed',
    `last_health_check_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent automated health check performed on the playout feed to verify operational status and signal quality. | Column last_health_check_timestamp (TIMESTAMP) in distribution.playout_feed',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when the playout feed record was last modified, capturing the most recent update event for change tracking and audit compliance. | Column modified_timestamp (TIMESTAMP) in distribution.playout_feed',
    `multicast_address` STRING COMMENT 'Multicast IP address used for distributing the playout feed to multiple receivers simultaneously in IP-based broadcast networks. | Column multicast_address (STRING) in distribution.playout_feed',
    `operational_status` STRING COMMENT 'Current operational state of the playout feed indicating whether it is actively broadcasting, on standby for failover, offline, under maintenance, experiencing errors, or in testing mode. | Column operational_status (STRING) in distribution.playout_feed. Valid values are `active|standby|offline|maintenance|error|testing`',
    `output_format` STRING COMMENT 'Physical or network output format of the playout feed: Serial Digital Interface (SDI) for baseband video, Internet Protocol (IP) for network streaming, Asynchronous Serial Interface (ASI) for MPEG transport streams, Secure Reliable Transport (SRT), Reliable Internet Stream Transport (RIST), or Network Device Interface (NDI). | Column output_format (STRING) in distribution.playout_feed. Valid values are `SDI|IP|ASI|SRT|RIST|NDI`',
    `playout_server_code` STRING COMMENT 'Identifier of the physical or virtual playout server assigned to generate this feed. Links the feed to the automation infrastructure. | Column playout_server_code (STRING) in distribution.playout_feed',
    `port_number` STRING COMMENT 'Network port number used for the playout feed output connection in IP-based delivery configurations. | Column port_number (INT) in distribution.playout_feed',
    `provisioned_date` DATE COMMENT 'Date when the playout feed was initially provisioned and configured in the playout automation system. | Column provisioned_date (DATE) in distribution.playout_feed',
    `redundancy_mode` STRING COMMENT 'Redundancy configuration for the playout feed: none (single feed), hot standby (backup ready to take over), active-active (both feeds broadcasting simultaneously), or N+1 (shared backup for multiple feeds). | Column redundancy_mode (STRING) in distribution.playout_feed. Valid values are `none|hot_standby|active_active|N+1`',
    `scte35_enabled` BOOLEAN COMMENT 'Indicates whether SCTE-35 digital program insertion cue messages are enabled in the playout feed for Dynamic Ad Insertion (DAI) and program segmentation. | Column scte35_enabled (BOOLEAN) in distribution.playout_feed',
    `service_identifier` STRING COMMENT 'DVB Service ID or ATSC program number identifying the service within the transport stream for Electronic Program Guide (EPG) and receiver tuning. | Column service_identifier (INT) in distribution.playout_feed',
    `sla_tier` STRING COMMENT 'Service level tier assigned to this playout feed defining uptime guarantees, response times, and support priority: platinum (highest), gold, silver, bronze, or standard. | Column sla_tier (STRING) in distribution.playout_feed. Valid values are `platinum|gold|silver|bronze|standard`',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.playout_feed',
    `subtitle_format` STRING COMMENT 'Subtitle or closed caption format embedded in the playout feed: DVB subtitles, Teletext, CEA-608, CEA-708, Timed Text Markup Language (TTML), or Web Video Text Tracks (WebVTT). | Column subtitle_format (STRING) in distribution.playout_feed. Valid values are `DVB|Teletext|CEA-608|CEA-708|TTML|WebVTT`',
    `transport_stream_identifier` STRING COMMENT 'MPEG Transport Stream ID (TSID) assigned to this playout feed for multiplexing and demultiplexing in broadcast distribution networks. | Column transport_stream_identifier (INT) in distribution.playout_feed',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.playout_feed',
    `uptime_target_percent` DECIMAL(18,2) COMMENT 'Target uptime percentage for the playout feed as defined in the Service Level Agreement (SLA), typically 99.9% or higher for mission-critical broadcast feeds. | Column uptime_target_percent (DECIMAL(5,2)) in distribution.playout_feed',
    `video_bitrate_mbps` DECIMAL(18,2) COMMENT 'Target video bitrate in megabits per second (Mbps) for the playout feed output, determining video quality and bandwidth consumption. | Column video_bitrate_mbps (DECIMAL(8,3)) in distribution.playout_feed',
    `video_codec` STRING COMMENT 'Video compression codec used for encoding the playout feed output: H.264 (AVC), H.265 (HEVC), MPEG-2, AV1, or VP9. | Column video_codec (STRING) in distribution.playout_feed. Valid values are `H.264|H.265|MPEG-2|AV1|VP9`',
    `video_resolution` STRING COMMENT 'Output video resolution class: Standard Definition (SD), High Definition (HD), Full High Definition (FHD), Ultra High Definition (UHD), 4K, or 8K. | Column video_resolution (STRING) in distribution.playout_feed. Valid values are `SD|HD|FHD|UHD|4K|8K`',
    CONSTRAINT pk_playout_feed PRIMARY KEY(`playout_feed_id`)
) COMMENT 'Master record for each discrete playout feed managed through Ericsson MediaFirst, representing a configured output stream from the playout automation system. Captures feed name, associated delivery channel, playout server assignment, output format (SDI, IP, ASI), transport stream parameters, graphics/branding overlay configuration, automation mode (fully automated, semi-automated, manual), redundancy configuration, and current operational status. The operational anchor linking scheduling to physical signal delivery. | Unity Catalog table: media_broadcasting_ecm.distribution.playout_feed';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`deal` (
    `deal_id` BIGINT COMMENT 'Primary key for deal | Column deal_id (BIGINT) in distribution.deal',
    `distribution_partner_id` BIGINT COMMENT 'Reference to the OTT platform, FAST aggregator, syndication buyer, or international distributor party to this deal. | Column distribution_partner_id (BIGINT) in distribution.deal',
    `dsp_id` BIGINT COMMENT 'FK to demand-side platform',
    `exchange_id` BIGINT COMMENT 'FK to ad exchange',
    `license_agreement_id` BIGINT COMMENT 'Foreign key linking to rights.license_agreement. Business justification: Distribution deals with partners are governed by underlying content license agreements. Critical for validating distribution rights chain, ensuring revenue share terms align with license obligations,  | Column license_agreement_id (BIGINT) in rights.deal',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Distribution deals are high-value contracts requiring business development owner for negotiations, revenue forecasting, MG tracking, and relationship management. Essential for commission tracking, app | Column owner_employee_id (BIGINT) in workforce.deal',
