    `created_by_user` STRING COMMENT 'User ID or system identifier that created this playout schedule entry. Used for accountability and workflow tracking. | Column created_by_user (STRING) in distribution.playout',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this playout event was created in the scheduling system. Used for audit trail and schedule change tracking. | Column created_timestamp (TIMESTAMP) in distribution.playout',
    `end_timestamp` TIMESTAMP COMMENT 'Scheduled end timestamp for when this media asset completes transmission on this delivery channel. Calculated from start time plus asset duration plus any padding. | Column end_timestamp (TIMESTAMP) in distribution.playout',
    `playout_status` STRING COMMENT 'Current operational status of this playout event: scheduled (future), in_progress (currently transmitting), completed (successfully aired), failed (technical failure), cancelled (removed from schedule), preempted (replaced by breaking news or priority content). | Column playout_status (STRING) in distribution.playout',
    `preemption_reason` STRING COMMENT 'Business reason if this playout event was preempted or cancelled (e.g., breaking news, technical failure, rights issue, schedule change). Null for completed playouts. | Column preemption_reason (STRING) in distribution.playout',
    `priority` STRING COMMENT 'Priority classification for this playout event. Breaking news and critical content may preempt standard programming. Used by playout automation for conflict resolution. | Column priority (STRING) in distribution.playout',
    `sequence_number` STRING COMMENT 'Sequential position of this asset within the channels playout schedule for the broadcast day. Used for playlist ordering and EPG generation. | Column sequence_number (INT) in distribution.playout',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.playout',
    `start_timestamp` TIMESTAMP COMMENT 'Scheduled start timestamp for when this media asset begins transmission on this delivery channel. Used for EPG scheduling and playout automation. | Column start_timestamp (TIMESTAMP) in distribution.playout',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.playout',
    CONSTRAINT pk_playout PRIMARY KEY(`playout_id`)
) COMMENT 'This association product represents the scheduled playout event between a delivery channel and a media asset. It captures the operational scheduling and transmission of specific media assets through specific delivery channels. Each record links one delivery channel to one media asset with playout-specific attributes including timing, sequencing, ad insertion configuration, and blackout rules that exist only in the context of this scheduled transmission.. Existence Justification: In media broadcasting operations, the same media asset is scheduled for playout across multiple delivery channels (e.g., a news segment airs on the main linear channel, regional feeds, and FAST channels), and each delivery channel transmits many different media assets throughout the broadcast day. Playout scheduling is an operational business process where traffic and scheduling teams actively create, modify, and manage playout events with channel-specific timing, ad insertion rules, blackout restrictions, and sequencing. This is not an analytical correlation but a core operational entity. | Unity Catalog table: media_broadcasting_ecm.distribution.playout Akamai CDN integration supported. EBU R128/ATSC A/85 audio loudness standards applicable.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`channel_compliance` (
    `channel_compliance_id` BIGINT COMMENT 'Unique identifier for this channel-obligation compliance record. Primary key. | Column channel_compliance_id (BIGINT) in distribution.channel_compliance',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to the delivery channel subject to this compliance obligation | Column delivery_channel_id (BIGINT) in distribution.channel_compliance',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to the regulatory obligation applicable to this channel | Column regulatory_obligation_id (BIGINT) in compliance.channel_compliance',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in distribution.channel_compliance',
    `_source_code` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in distribution.channel_compliance',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in distribution.channel_compliance',
    `compliance_notes` STRING COMMENT 'Free-text notes documenting channel-specific compliance considerations, remediation actions, or special circumstances for this obligation. | Column compliance_notes (STRING) in distribution.channel_compliance',
    `compliance_status` STRING COMMENT 'Current compliance status of this specific channel with respect to this specific obligation. Tracks whether the channel is meeting the regulatory requirement. | Column compliance_status (STRING) in distribution.channel_compliance',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in distribution.channel_compliance',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this compliance record was created in the system. | Column created_timestamp (TIMESTAMP) in distribution.channel_compliance',
    `effective_date` DATE COMMENT 'Date when this obligation became applicable to this channel. May differ from the obligations general effective_date if the channel launched after the regulation took effect. | Column effective_date (DATE) in distribution.channel_compliance',
    `exemption_basis` STRING COMMENT 'Legal or regulatory basis for exemption if this channel is exempt from this obligation (e.g., low-power exemption, OTT platform exclusion, grandfathered status). Null if no exemption applies. | Column exemption_basis (STRING) in distribution.channel_compliance',
    `expiration_date` DATE COMMENT 'Date when this obligation ceases to apply to this channel (e.g., channel retirement, exemption granted, regulation superseded). Null for ongoing obligations. | Column expiration_date (DATE) in distribution.channel_compliance',
    `last_audit_date` DATE COMMENT 'Date of the most recent internal or external audit of this channels compliance with this obligation. | Column last_audit_date (DATE) in distribution.channel_compliance',
    `last_compliance_review_date` DATE COMMENT 'Date when compliance of this channel with this obligation was last reviewed or assessed. Channel-specific review date distinct from the obligation-level review. | Column last_compliance_review_date (DATE) in distribution.channel_compliance',
    `next_audit_date` DATE COMMENT 'Scheduled date for the next audit of this channels compliance with this obligation. | Column next_audit_date (DATE) in distribution.channel_compliance',
    `next_filing_date` DATE COMMENT 'Scheduled date for the next compliance filing or submission for this channel-obligation combination. Channel-specific deadline that may differ from the general obligation deadline based on channel launch date or exemption status. | Column next_filing_date (DATE) in distribution.channel_compliance',
    `reporting_frequency` STRING COMMENT 'How often this channel must report or demonstrate compliance with this obligation. May differ from the obligations general compliance_frequency based on channel type or exemption status. | Column reporting_frequency (STRING) in distribution.channel_compliance',
    `responsible_contact` STRING COMMENT 'Name or identifier of the individual responsible for ensuring this channels compliance with this specific obligation. May be a channel manager, compliance officer, or legal counsel. | Column responsible_contact (STRING) in distribution.channel_compliance',
    `source_code` STRING COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in distribution.channel_compliance',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in distribution.channel_compliance',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this compliance record was last updated. | Column updated_timestamp (TIMESTAMP) in distribution.channel_compliance',
    CONSTRAINT pk_channel_compliance PRIMARY KEY(`channel_compliance_id`)
) COMMENT 'This association product represents the compliance relationship between delivery channels and regulatory obligations. It captures channel-specific compliance status, review schedules, exemptions, and filing deadlines for each obligation applicable to each channel. Each record links one delivery channel to one regulatory obligation with attributes that exist only in the context of this specific compliance relationship.. Existence Justification: In media broadcasting operations, each delivery channel (linear, OTT, FAST) is subject to multiple regulatory obligations (closed captioning, EAS participation, childrens programming quotas, political advertising disclosure, content rating requirements). Conversely, each regulatory obligation applies to multiple channels based on channel type, market, and platform. Compliance teams actively manage channel-specific compliance status, review schedules, exemptions, and filing deadlines for each channel-obligation pair as a distinct operational record. | Unity Catalog table: media_broadcasting_ecm.distribution.channel_compliance';

