    `secondary_affiliation` STRING COMMENT 'Secondary network affiliation if any',
    `station_group_name` STRING COMMENT 'Station group owner (Sinclair, Nexstar, Tegna)',
    `station_name` STRING COMMENT 'Station display name',
    `station_type` STRING COMMENT 'Station type (O&O, affiliate, independent)',
    `updated_timestamp` TIMESTAMP COMMENT 'Record last update timestamp',
    `virtual_channel` STRING COMMENT 'Virtual channel number displayed to viewers',
    CONSTRAINT pk_affiliate_station PRIMARY KEY(`affiliate_station_id`)
) COMMENT 'Represents local affiliate stations in a station group (Sinclair/Nexstar/Tegna) with call sign, DMA, network affiliation';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`clip_distribution_event` (
    `clip_distribution_event_id` BIGINT COMMENT 'Primary key for clip distribution event',
    `media_asset_id` BIGINT COMMENT 'FK to the source media asset',
    `social_distribution_outlet_id` BIGINT COMMENT 'FK to the social outlet',
    `title_id` BIGINT COMMENT 'FK to the content title',
    `clip_duration_seconds` STRING COMMENT 'Duration of the distributed clip',
    `comment_count` BIGINT COMMENT 'Total comment count',
    `created_timestamp` TIMESTAMP COMMENT 'Record creation timestamp',
    `distribution_status` STRING COMMENT 'Status (pending, uploaded, published, removed, failed)',
    `like_count` BIGINT COMMENT 'Total like/reaction count',
    `platform_content_code` STRING COMMENT 'Platform-specific content identifier (YouTube video ID, etc.)',
    `platform_url` STRING COMMENT 'Full URL to the content on the platform',
    `publish_timestamp` TIMESTAMP COMMENT 'When the content was made public',
    `removal_reason` STRING COMMENT 'Reason for removal (rights_expired, takedown_request, policy_violation)',
    `removal_timestamp` TIMESTAMP COMMENT 'When the content was removed if applicable',
    `revenue_amount` DECIMAL(18,2) COMMENT 'Revenue generated from this distribution',
    `revenue_currency_code` STRING COMMENT 'Currency code for revenue',
    `share_count` BIGINT COMMENT 'Total share count',
    `updated_timestamp` TIMESTAMP COMMENT 'Record last update timestamp',
    `upload_timestamp` TIMESTAMP COMMENT 'When the content was uploaded',
    `view_count` BIGINT COMMENT 'Total view count',
    CONSTRAINT pk_clip_distribution_event PRIMARY KEY(`clip_distribution_event_id`)
) COMMENT 'Clip distribution event to social platforms';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`social_distribution_outlet` (
    `social_distribution_outlet_id` BIGINT COMMENT 'Primary key for social distribution outlet',
    `active_flag` BOOLEAN COMMENT 'Whether this outlet is currently active for distribution',
    `api_endpoint_url` STRING COMMENT 'API endpoint for content upload and management',
    `channel_handle` STRING COMMENT 'Official channel handle or username on the platform',
    `content_id_enabled_flag` BOOLEAN COMMENT 'Whether Content ID or similar rights management is enabled',
    `created_timestamp` TIMESTAMP COMMENT 'Record creation timestamp',
    `follower_count` BIGINT COMMENT 'Current follower/subscriber count',
    `max_video_duration_seconds` STRING COMMENT 'Maximum allowed video duration on the platform',
    `monetization_enabled_flag` BOOLEAN COMMENT 'Whether monetization is enabled on this outlet',
    `oauth_client_code` STRING COMMENT 'OAuth client identifier for API authentication',
    `outlet_name` STRING COMMENT 'Name of the social platform (YouTube, TikTok, Instagram, etc.)',
    `outlet_type` STRING COMMENT 'Type of outlet (video_sharing, short_form, social_network)',
    `supported_aspect_ratios` STRING COMMENT 'Comma-separated list of supported aspect ratios',
    `updated_timestamp` TIMESTAMP COMMENT 'Record last update timestamp',
    `verification_status` STRING COMMENT 'Platform verification status (verified, unverified, pending)',
    CONSTRAINT pk_social_distribution_outlet PRIMARY KEY(`social_distribution_outlet_id`)
) COMMENT 'YouTube/TikTok/IG distribution outlet';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`distribution_network_clearance` (
    `distribution_network_clearance_id` BIGINT COMMENT 'Primary key for network clearance',
    `affiliate_station_id` BIGINT COMMENT 'FK to affiliate station',
    `program_schedule_id` BIGINT COMMENT 'FK to program schedule',
    `title_id` BIGINT COMMENT 'FK to content title',
    `clearance_status` STRING COMMENT 'Status (cleared, preempted, delayed, make-good)',
    `created_timestamp` TIMESTAMP COMMENT 'Record creation timestamp',
    `local_air_date` DATE COMMENT 'Local air date',
    `local_air_time` TIMESTAMP COMMENT 'Local air time',
    `make_good_date` DATE COMMENT 'Make-good air date',
    `make_good_scheduled_flag` BOOLEAN COMMENT 'Whether make-good is scheduled',
    `make_good_time` TIMESTAMP COMMENT 'Make-good air time',
    `network_compensation_impact_flag` BOOLEAN COMMENT 'Whether clearance affects network compensation',
    `network_feed_date` DATE COMMENT 'Date of network feed',
    `network_feed_time` TIMESTAMP COMMENT 'Time of network feed',
    `notes` STRING COMMENT 'Additional notes',
    `preemption_content` STRING COMMENT 'What content replaced network feed',
    `preemption_reason` STRING COMMENT 'Reason for preemption if applicable',
    `updated_timestamp` TIMESTAMP COMMENT 'Record last update timestamp',
    CONSTRAINT pk_distribution_network_clearance PRIMARY KEY(`distribution_network_clearance_id`)
) COMMENT 'Network program clearance tracking for affiliate stations including preemption and make-good scheduling.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`distribution_local_avail_inventory` (
    `distribution_local_avail_inventory_id` BIGINT COMMENT 'Primary key for local avail inventory',
    `ad_break_id` BIGINT COMMENT 'Reference to ad break',
    `affiliate_station_id` BIGINT COMMENT 'Reference to affiliate station',
    `daypart_id` BIGINT COMMENT 'Reference to daypart',
    `avail_date` DATE COMMENT 'Date of availability',
    `avail_duration_seconds` STRING COMMENT 'Duration of avail in seconds',
    `avail_end_time` TIMESTAMP COMMENT 'End time of avail window',
    `avail_start_time` TIMESTAMP COMMENT 'Start time of avail window',
    `avail_type` STRING COMMENT 'Type of avail (local, regional, national)',
    `created_timestamp` TIMESTAMP COMMENT 'Record creation timestamp',
    `estimated_impressions` BIGINT COMMENT 'Estimated impressions',
    `rate_card_rate` DECIMAL(18,2) COMMENT 'Rate card price for avail',
    `sold_flag` BOOLEAN COMMENT 'Whether avail has been sold',
    `sold_rate` DECIMAL(18,2) COMMENT 'Actual sold rate if sold',
    `updated_timestamp` TIMESTAMP COMMENT 'Record last update timestamp',
    CONSTRAINT pk_distribution_local_avail_inventory PRIMARY KEY(`distribution_local_avail_inventory_id`)
) COMMENT 'Local advertising avail inventory for affiliate stations';

